import type { CareerQuestion } from "./rrt-questions";

export const otaQuestions: CareerQuestion[] = [
  { id: "ota-001", stem: "An OTA is working with a client who had a posterior approach total hip replacement 2 days ago. Which activity must be avoided?", options: ["Seated ankle pumps", "Standing hip abduction with abduction pillow", "Bending forward to put on shoes with hip flexion >90°", "Supine hip extension exercises"], correctIndex: 2, rationale: "Posterior approach THR precautions prohibit hip flexion beyond 90° to prevent posterior dislocation. Bending forward to don shoes exceeds this limit.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-002", stem: "A client with C6 spinal cord injury wants to feed independently. Which adaptive device should the OTA recommend?", options: ["Standard fork and knife", "Universal cuff with built-up utensil", "Weighted utensils", "Long-handled reacher"], correctIndex: 1, rationale: "C6 SCI results in absent hand grasp but preserved wrist extension. A universal cuff straps the utensil to the hand, and tenodesis allows functional feeding.", difficulty: 2, category: "Therapeutic Intervention", topic: "Assistive Devices" },
  { id: "ota-003", stem: "An OTA is assessing a 3-year-old child's pencil grasp. The child uses a palmar supinate grasp. What should the OTA document?", options: ["Abnormal grasp requiring immediate intervention", "Age-appropriate grasp pattern; dynamic tripod expected by 3.5-4 years", "Delayed development requiring referral to neurology", "Normal grasp that will persist through school age"], correctIndex: 1, rationale: "Palmar grasp patterns are typical in toddlers. The dynamic tripod grasp develops at approximately 3.5-4 years. Premature intervention for mature grasp is not recommended.", difficulty: 2, category: "Patient Care Planning", topic: "Pediatric Rehabilitation" },
  { id: "ota-004", stem: "A client with Alzheimer's disease is assessed at Allen Cognitive Level 4. What can this client be expected to do?", options: ["Independently prepare complex meals and manage finances", "Perform familiar routine tasks with visual cues but cannot problem-solve novel situations", "Only perform automatic reflexive actions", "Learn new complex skills with minimal repetition"], correctIndex: 1, rationale: "ACL 4 indicates goal-directed activity with familiar tasks. The client can complete routine activities with visual cues but cannot solve new problems or recognize errors without supervision.", difficulty: 3, category: "Clinical Scenarios", topic: "Geriatric Rehabilitation" },
  { id: "ota-005", stem: "Which teaching strategy has the child complete the LAST step of a dressing task first, then progressively adds earlier steps?", options: ["Forward chaining", "Backward chaining", "Whole-task approach", "Errorless learning"], correctIndex: 1, rationale: "Backward chaining teaches the last step first so the child experiences task completion success immediately, building motivation and self-efficacy.", difficulty: 1, category: "Therapeutic Intervention", topic: "Pediatric Rehabilitation" },
  { id: "ota-006", stem: "An OTA is conducting a home safety assessment for a client at risk for falls. Which modification is the HIGHEST priority?", options: ["Installing decorative curtains", "Removing throw rugs from walkways", "Changing wall paint color for aesthetics", "Adding a bookshelf in the living room"], correctIndex: 1, rationale: "Throw rugs are a major fall hazard. Removing them eliminates tripping risk and is a high-priority environmental modification for fall prevention.", difficulty: 1, category: "Safety", topic: "Geriatric Rehabilitation" },
  { id: "ota-007", stem: "A client is 3 weeks post flexor tendon repair of the hand. Which exercise is appropriate at this stage?", options: ["Aggressive resistive exercise", "Passive ROM within protocol parameters", "Heavy grip strengthening with putty", "Unrestricted active ROM"], correctIndex: 1, rationale: "At 3 weeks post flexor tendon repair (fibroplasia phase), passive ROM within the surgeon's protocol is appropriate. Resistive exercise risks tendon rupture at this healing stage.", difficulty: 3, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-008", stem: "The OTA is working with a client who has right hemisphere stroke. Which deficit is MOST commonly associated with this lesion?", options: ["Wernicke's aphasia", "Left unilateral neglect", "Right-sided hemiplegia", "Broca's aphasia"], correctIndex: 1, rationale: "Right hemisphere stroke most commonly causes left unilateral neglect, where the client fails to attend to stimuli on the left side of the body and environment.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "ota-009", stem: "An OTA is training a client to use a sliding board transfer. What is the correct setup?", options: ["Place the board from the client's feet to the target surface", "Position the board under the client's buttocks angled toward the transfer surface with wheelchair brakes locked", "Have the client stand first, then place the board", "Remove the wheelchair cushion but leave brakes unlocked"], correctIndex: 1, rationale: "Sliding board transfers require the board under the buttock bridging to the target surface, wheelchair brakes locked, armrest removed, and the client uses push-ups to scoot across.", difficulty: 2, category: "Safety", topic: "Patient Mobility Techniques" },
  { id: "ota-010", stem: "A client with rheumatoid arthritis asks about joint protection techniques. Which principle should the OTA emphasize?", options: ["Use the smallest joints possible for all tasks", "Maintain a tight grip on objects for as long as possible", "Use the largest joint available and distribute forces across multiple joints", "Avoid all physical activity to protect joints"], correctIndex: 2, rationale: "Joint protection principles include using the largest joint possible, distributing forces, avoiding sustained grip and static positions, and respecting pain signals.", difficulty: 1, category: "Patient Care Planning", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-011", stem: "An OTA is grading a fine motor activity for a client with limited dexterity. Which modification makes the task EASIER?", options: ["Decrease object size", "Increase time pressure", "Provide larger, textured objects with stable surfaces", "Remove all visual feedback"], correctIndex: 2, rationale: "Grading down involves increasing object size, adding texture for better grip, providing stable surfaces, and reducing precision requirements to match client abilities.", difficulty: 1, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "ota-012", stem: "A client with T4 SCI suddenly develops a pounding headache and blood pressure of 210/120 during therapy. What should the OTA do FIRST?", options: ["Continue the therapy session as planned", "Have the client lie flat and elevate legs", "Sit the client upright immediately and check for noxious stimuli", "Administer oral antihypertensive medication"], correctIndex: 2, rationale: "These symptoms indicate autonomic dysreflexia, a life-threatening emergency. Sit the client upright to lower BP, check for noxious stimuli (kinked catheter, tight clothing), and notify medical team.", difficulty: 3, category: "Safety", topic: "Neurological Rehabilitation" },
  { id: "ota-013", stem: "Which standardized assessment measures a client's self-identified priorities for occupational performance?", options: ["FIM (Functional Independence Measure)", "COPM (Canadian Occupational Performance Measure)", "MMT (Manual Muscle Testing)", "Berg Balance Scale"], correctIndex: 1, rationale: "The COPM is a client-centered measure that identifies and prioritizes occupational performance issues based on the client's own perception of importance, performance, and satisfaction.", difficulty: 2, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-014", stem: "The OTA is positioning a resting hand splint. What is the correct 'safe position' for the wrist and fingers?", options: ["Wrist flexion, MCP extension, IP flexion", "Wrist 20-30° extension, MCP 70-90° flexion, IP extension, thumb abduction", "Full wrist and finger extension", "Wrist neutral, all joints at 0°"], correctIndex: 1, rationale: "The safe (anti-deformity) position maintains wrist in 20-30° extension, MCPs in 70-90° flexion, IPs in extension, and thumb in abduction to preserve collateral ligament length.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-015", stem: "An OTA is working in a school-based setting. Which factor MUST guide all OT interventions?", options: ["Medical necessity determined by physician order", "Educational relevance supporting classroom participation", "Insurance authorization requirements", "Parent's personal therapy goals"], correctIndex: 1, rationale: "School-based OT services must be educationally relevant under IDEA. All interventions must support the child's ability to participate in and benefit from their educational program.", difficulty: 2, category: "Patient Care Planning", topic: "Pediatric Rehabilitation" },
  { id: "ota-016", stem: "A client scores 15 seconds on the Timed Up and Go (TUG) test. What does this result indicate?", options: ["Normal mobility with no fall risk", "Increased fall risk requiring intervention", "Excellent balance and function", "Need for wheelchair-only mobility"], correctIndex: 1, rationale: "A TUG score >12 seconds indicates increased fall risk. The OTA should implement fall prevention strategies including environmental modification, balance training, and assistive device evaluation.", difficulty: 2, category: "Clinical Scenarios", topic: "Geriatric Rehabilitation" },
  { id: "ota-017", stem: "Which frame of reference emphasizes the interaction between person, environment, and occupation?", options: ["Biomechanical", "Neurodevelopmental treatment (NDT)", "Person-Environment-Occupation (PEO)", "Cognitive-behavioral"], correctIndex: 2, rationale: "The PEO model analyzes the dynamic interaction between the person's abilities, the demands of the environment, and the requirements of the occupation to identify barriers and supports.", difficulty: 2, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "ota-018", stem: "An OTA is working with a client who has a C5 SCI. Which functional outcome is realistic?", options: ["Independent dressing and feeding without equipment", "Feeding with setup and adaptive equipment", "Independent ambulation with crutches", "Independent driving a standard vehicle"], correctIndex: 1, rationale: "C5 SCI preserves deltoid and biceps function. With adaptive equipment and setup assistance, the client can feed independently but requires assistance for most other ADLs.", difficulty: 3, category: "Patient Care Planning", topic: "Neurological Rehabilitation" },
  { id: "ota-019", stem: "Which energy conservation technique involves alternating between activity and rest periods throughout the day?", options: ["Planning", "Prioritizing", "Pacing", "Positioning"], correctIndex: 2, rationale: "Pacing involves alternating between activity and rest periods to manage fatigue, resting before exhaustion and breaking tasks into manageable segments.", difficulty: 1, category: "Therapeutic Intervention", topic: "Geriatric Rehabilitation" },
  { id: "ota-020", stem: "The OTA observes that a client's wheelchair seat is too wide. What is the primary concern?", options: ["The wheelchair will be too heavy to propel", "Reduced trunk support leading to poor posture and increased fall risk", "The wheelchair will be too expensive", "The client will not be able to reach the push rims"], correctIndex: 1, rationale: "A wheelchair that is too wide provides inadequate lateral trunk support, promotes poor posture, reduces propulsion efficiency, and increases the risk of sliding and pressure injuries.", difficulty: 2, category: "Safety", topic: "Assistive Devices" },
  { id: "ota-021", stem: "A client with left hemiplegia needs to transfer from bed to wheelchair. On which side should the wheelchair be placed?", options: ["Left (affected) side", "Right (unaffected) side", "At the foot of the bed", "Either side is equally appropriate"], correctIndex: 1, rationale: "The wheelchair should be placed on the client's stronger (right/unaffected) side so the client leads with the stronger leg during the stand-pivot transfer for maximum stability.", difficulty: 2, category: "Safety", topic: "Patient Mobility Techniques" },
  { id: "ota-022", stem: "An OTA is implementing constraint-induced movement therapy (CIMT) for a client post-stroke. What does this involve?", options: ["Constraining the affected arm to prevent movement", "Restraining the unaffected arm while intensively training the affected arm", "Using bilateral activities exclusively", "Avoiding all upper extremity activities for 6 weeks"], correctIndex: 1, rationale: "CIMT restrains the unaffected UE for 90% of waking hours while providing intensive, repetitive functional training of the affected arm to overcome learned nonuse.", difficulty: 3, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "ota-023", stem: "A client with a Sensory Profile showing 'sensory avoiding' patterns becomes distressed by loud noises and bright lights. What intervention is appropriate?", options: ["Increase sensory exposure to desensitize the client", "Modify the environment to reduce sensory input and provide calming strategies", "Ignore the behavior and continue therapy", "Refer immediately to psychiatry"], correctIndex: 1, rationale: "Sensory avoiders have low neurological thresholds and active self-regulation. Reducing environmental sensory input and providing calming strategies supports participation.", difficulty: 2, category: "Therapeutic Intervention", topic: "Pediatric Rehabilitation" },
  { id: "ota-024", stem: "Which standardized tool measures functional independence across motor and cognitive domains on a 1-7 scale?", options: ["Barthel Index", "Functional Independence Measure (FIM)", "Katz Index", "Allen Cognitive Level Screen"], correctIndex: 1, rationale: "The FIM measures 18 items across motor (13) and cognitive (5) domains on a 1 (total assist) to 7 (complete independence) scale, providing a standardized measure of disability.", difficulty: 1, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-025", stem: "An OTA notices a client's splint is causing a red pressure mark over the ulnar styloid. What should the OTA do?", options: ["Continue use and monitor the mark", "Remove the splint, pad the area, and report to the supervising OT", "Tell the client to stop wearing the splint permanently", "Apply ice to the red area and continue splint use"], correctIndex: 1, rationale: "A red pressure mark indicates excessive pressure. The OTA should remove the splint, pad the pressure area, and report to the supervising OT for splint modification to prevent skin breakdown.", difficulty: 2, category: "Safety", topic: "Assistive Devices" },
  { id: "ota-026", stem: "In Brunnstrom Stage 3 of motor recovery after stroke, what movement pattern is characteristic?", options: ["Flaccidity with no voluntary movement", "Voluntary synergy patterns emerge", "Isolated voluntary movement outside synergy", "Normal motor function returns"], correctIndex: 1, rationale: "Brunnstrom Stage 3 is characterized by the emergence of voluntary synergy patterns. The client can initiate movement but only within stereotypical flexion and extension synergies.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "ota-027", stem: "A client with bilateral LE amputations needs to transfer from wheelchair to bed. Which transfer method is most appropriate?", options: ["Stand-pivot transfer", "Sliding board transfer", "Independent walk-and-sit transfer", "Rolling transfer from standing"], correctIndex: 1, rationale: "Bilateral LE amputations prevent standing. A sliding board transfer uses UE strength to bridge the gap between wheelchair and bed without requiring lower extremity weight-bearing.", difficulty: 2, category: "Patient Care Planning", topic: "Patient Mobility Techniques" },
  { id: "ota-028", stem: "An OTA is working with a client who has dementia. The client becomes agitated during a bathing activity. What is the BEST response?", options: ["Insist on completing the bath to maintain hygiene", "Stop the activity, use a calm voice, and simplify the task or try again later", "Leave the client alone in the bathroom", "Restrain the client to complete the bath safely"], correctIndex: 1, rationale: "When a client with dementia becomes agitated, stop the provoking activity, use a calm reassuring voice, simplify the task, and reattempt later when the client is calmer.", difficulty: 2, category: "Safety", topic: "Geriatric Rehabilitation" },
  { id: "ota-029", stem: "What is the primary purpose of activity analysis in OT?", options: ["To diagnose medical conditions", "To systematically examine an activity's component demands and therapeutic potential", "To prescribe medications for treatment", "To determine insurance coverage"], correctIndex: 1, rationale: "Activity analysis systematically examines an activity's demands (motor, cognitive, social, sensory) to understand its therapeutic potential and guide intervention planning.", difficulty: 1, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "ota-030", stem: "A client who had a stroke 1 week ago presents with flaccid upper extremity. Which Brunnstrom stage is this?", options: ["Stage 1 — Flaccidity", "Stage 3 — Voluntary synergies", "Stage 5 — Isolated movement", "Stage 6 — Near normal"], correctIndex: 0, rationale: "Stage 1 of Brunnstrom recovery is characterized by flaccidity (no voluntary movement) in the affected extremity, which typically occurs in the acute phase after stroke.", difficulty: 1, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "ota-031", stem: "An OTA is training a client with arthritis to open jars. Which adaptive approach uses joint protection principles?", options: ["Use maximum finger grip force to open the jar", "Use a Dycem mat for stability and an electric jar opener to reduce joint stress", "Hold the jar with one hand and twist forcefully with the other", "Avoid opening any jars and depend on others"], correctIndex: 1, rationale: "Joint protection reduces stress on affected joints. A Dycem mat prevents jar slipping, and an electric or adapted jar opener reduces the force required, protecting finger and wrist joints.", difficulty: 2, category: "Therapeutic Intervention", topic: "Assistive Devices" },
  { id: "ota-032", stem: "Which measurement tool assesses spasticity on a 0-4 scale?", options: ["Manual Muscle Test", "Modified Ashworth Scale", "Goniometry", "FIM"], correctIndex: 1, rationale: "The Modified Ashworth Scale grades spasticity from 0 (no increase in tone) to 4 (limb rigid in flexion or extension), providing a standardized clinical measure of muscle tone.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "ota-033", stem: "A client is wearing a wrist cock-up splint after a distal radius fracture. What is the primary purpose of this splint?", options: ["To increase wrist flexion ROM", "To support and immobilize the wrist in a functional position during healing", "To strengthen the wrist flexors", "To increase grip strength"], correctIndex: 1, rationale: "A wrist cock-up splint immobilizes the wrist in slight extension (functional position) during fracture healing while allowing finger movement for light functional use.", difficulty: 1, category: "Therapeutic Intervention", topic: "Assistive Devices" },
  { id: "ota-034", stem: "An OTA notices a client performing a wheelchair transfer without locking the brakes. What is the appropriate action?", options: ["Allow the transfer to continue since the client initiated it", "Stop the transfer immediately and educate the client about brake-locking safety", "Document the incident and report at end of day", "Wait to see if the client falls before intervening"], correctIndex: 1, rationale: "Unlocked wheelchair brakes are the most common cause of wheelchair transfer falls. The OTA must immediately stop the unsafe transfer and educate the client on proper brake-locking protocol.", difficulty: 1, category: "Safety", topic: "Patient Mobility Techniques" },
  { id: "ota-035", stem: "Which model of practice examines volition, habituation, and performance capacity as determinants of occupational engagement?", options: ["Biomechanical frame of reference", "Model of Human Occupation (MOHO)", "Person-Environment-Occupation (PEO)", "Cognitive-behavioral frame"], correctIndex: 1, rationale: "MOHO examines three interacting components: volition (motivation for occupation), habituation (patterns and roles), and performance capacity (physical and mental abilities) within environmental context.", difficulty: 3, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "ota-036", stem: "A 4-month-old infant cannot hold their head up when placed in prone. What should the OTA consider?", options: ["This is within normal limits for a 4-month-old", "The infant may have a developmental delay — head control typically develops by 2-4 months", "Head control is not expected until 12 months", "No intervention is needed until the child is school age"], correctIndex: 1, rationale: "Head control in prone typically develops by 2-4 months. A 4-month-old who cannot hold the head up may have developmental delay warranting further assessment and early intervention.", difficulty: 2, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "ota-037", stem: "A client with C7 SCI is expected to achieve which level of independence?", options: ["Total dependence for all ADLs", "Independence in most ADLs including self-care and wheelchair mobility", "Independent ambulation with assistive devices", "Feeding only with adaptive equipment"], correctIndex: 1, rationale: "C7 SCI preserves triceps, wrist flexors, and finger extensors. Clients with C7 injuries can typically achieve independence in most ADLs, transfers, and wheelchair mobility.", difficulty: 2, category: "Patient Care Planning", topic: "Neurological Rehabilitation" },
  { id: "ota-038", stem: "An OTA is using therapeutic putty for hand strengthening. The client is a beginning level. Which putty resistance should be used?", options: ["Black (extra-firm) for maximum challenge", "Tan or yellow (extra-soft to soft) for beginning resistance", "Blue (firm) for moderate challenge", "No putty — only weights should be used"], correctIndex: 1, rationale: "Therapeutic putty progresses from tan (extra-soft) through yellow, red, green, blue, to black (extra-firm). Beginning clients start with the lowest resistance and progress gradually.", difficulty: 1, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "ota-039", stem: "What is the MOST important reason to document functional outcomes rather than just exercise performance?", options: ["Functional outcomes are faster to document", "Functional outcomes justify skilled OTA services and demonstrate treatment effectiveness", "Insurance companies only accept exercise data", "Functional outcomes are less objective than exercise data"], correctIndex: 1, rationale: "Functional outcome documentation demonstrates the skilled nature of OTA services and treatment effectiveness, justifying continued intervention and meeting payer requirements.", difficulty: 2, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "ota-040", stem: "A client reports pain at 7/10 during a therapeutic exercise. What should the OTA do?", options: ["Continue the exercise at the same intensity", "Increase the exercise intensity to build tolerance", "Stop or modify the activity — pain should not exceed 3-4/10 during exercise", "Document the pain level and continue without modification"], correctIndex: 2, rationale: "Pain exceeding 3-4/10 during therapeutic exercise may indicate tissue damage or inappropriate intensity. The OTA should modify or stop the activity and report to the supervising OT.", difficulty: 2, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "ota-041", stem: "An OTA is preparing a sensory diet for a child with sensory processing disorder. Which component is essential?", options: ["Providing identical sensory input every session regardless of response", "Individualized sensory activities scheduled throughout the day based on the child's sensory profile", "Limiting all sensory input to prevent overstimulation", "Using only auditory stimuli for intervention"], correctIndex: 1, rationale: "A sensory diet is an individualized plan of sensory activities scheduled throughout the day to maintain optimal arousal and support participation, based on the child's specific sensory profile.", difficulty: 2, category: "Therapeutic Intervention", topic: "Pediatric Rehabilitation" },
  { id: "ota-042", stem: "Which adaptive device would MOST benefit a client who cannot bend to reach their feet for sock donning?", options: ["Universal cuff", "Sock aid with long handles", "Built-up spoon", "Weighted pen"], correctIndex: 1, rationale: "A sock aid with long handles eliminates the need to bend forward to reach the feet, enabling independent sock donning while adhering to hip precautions or addressing limited flexibility.", difficulty: 1, category: "Therapeutic Intervention", topic: "Assistive Devices" },
  { id: "ota-043", stem: "The supervising OT asks the OTA to complete an initial evaluation for a new client. How should the OTA respond?", options: ["Complete the evaluation as requested", "Decline — initial evaluation is outside the OTA's scope of practice", "Complete the evaluation but note it was done by an OTA", "Ask another OTA to complete it instead"], correctIndex: 1, rationale: "Initial evaluation, establishing the diagnosis and prognosis, and creating the plan of care are outside the OTA's scope of practice. These are the OT's responsibility.", difficulty: 1, category: "Safety", topic: "Rehabilitation Principles" },
  { id: "ota-044", stem: "A client recovering from a stroke demonstrates the ability to voluntarily move the upper extremity but only in synergy patterns. Which Brunnstrom stage is this?", options: ["Stage 2", "Stage 3", "Stage 4", "Stage 5"], correctIndex: 1, rationale: "Stage 3 involves voluntary movement but only within synergy patterns (flexion synergy or extension synergy). Stage 4 begins with movement outside of synergy patterns.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "ota-045", stem: "An OTA is training a client in energy conservation for chronic fatigue. Which strategy is LEAST effective?", options: ["Sitting instead of standing during tasks", "Completing all tasks at once without rest breaks to finish faster", "Organizing work areas to reduce unnecessary reaching", "Using adaptive equipment to reduce physical demands"], correctIndex: 1, rationale: "Completing all tasks at once without rest breaks leads to exhaustion. Energy conservation requires pacing (alternating activity and rest), prioritizing tasks, and eliminating unnecessary effort.", difficulty: 1, category: "Patient Care Planning", topic: "Geriatric Rehabilitation" },
  { id: "ota-046", stem: "A client with upper extremity edema after a distal radius fracture. Which intervention sequence is appropriate?", options: ["Active ROM first, then apply compression", "Elevation, retrograde massage, compression, then active ROM", "Resistive exercise to push fluid out", "Dependent positioning followed by heat application"], correctIndex: 1, rationale: "Edema management follows a sequence: elevation above heart level, retrograde massage (distal to proximal), compression wrapping, and then gentle active ROM to promote venous and lymphatic return.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-047", stem: "In the OTPF-4, what is the difference between an 'occupation' and an 'activity'?", options: ["There is no difference", "An occupation has personal meaning and relevance to the client; an activity is a component task without personal meaning", "An activity is more complex than an occupation", "Occupations are only work-related tasks"], correctIndex: 1, rationale: "The OTPF-4 distinguishes occupations (daily activities with personal meaning and relevance) from activities (component tasks used therapeutically but without the client's personal context).", difficulty: 3, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "ota-048", stem: "An OTA observes a client using a gait belt during ambulation. What is the correct grip technique?", options: ["Grasp the belt from the top with palms facing down", "Grasp the belt from underneath with palms facing up", "Hold the client by their waistband", "Grip the client's arm above the elbow"], correctIndex: 1, rationale: "The gait belt is grasped from underneath with palms up, providing optimal control and leverage to safely guide the client to the ground if they begin to fall.", difficulty: 1, category: "Safety", topic: "Patient Mobility Techniques" },
  { id: "ota-049", stem: "Which assessment tool is used to determine cognitive function levels in clients with dementia, graded from Level 1 to Level 6?", options: ["Mini-Mental State Examination (MMSE)", "Allen Cognitive Level Screen (ACLS)", "Montreal Cognitive Assessment (MoCA)", "Glasgow Coma Scale"], correctIndex: 1, rationale: "The Allen Cognitive Level Screen measures cognitive function on a scale of 1-6, guiding OT intervention complexity and caregiver supervision needs for clients with dementia.", difficulty: 2, category: "Clinical Scenarios", topic: "Geriatric Rehabilitation" },
  { id: "ota-050", stem: "A client with a rotator cuff repair is 2 weeks post-surgery. Which exercise is appropriate?", options: ["Active overhead reaching", "Passive ROM within surgeon's protocol", "Resistive shoulder strengthening", "Throwing exercises"], correctIndex: 1, rationale: "At 2 weeks post-rotator cuff repair, only passive ROM within the surgeon's protocol is appropriate to protect the healing repair. Active and resistive exercises are introduced later.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-051", stem: "An OTA is implementing a cognitive rehabilitation program for a client with TBI at Rancho Level V. What characterizes this level?", options: ["No response to stimulation", "Confused and inappropriate behavior", "Confused but appropriate with maximal assistance", "Purposeful and appropriate — independent"], correctIndex: 1, rationale: "Rancho Level V is 'confused, inappropriate, non-agitated.' The client can follow simple commands but responses are random and non-purposeful. Structure and redirection are needed.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "ota-052", stem: "A client needs to button a shirt but has limited fine motor dexterity. Which adaptive device would help?", options: ["Universal cuff", "Button hook", "Sock aid", "Long-handled reacher"], correctIndex: 1, rationale: "A button hook has a wire loop that pulls through the buttonhole and around the button, enabling one-handed or limited-dexterity buttoning without fine motor precision.", difficulty: 1, category: "Therapeutic Intervention", topic: "Assistive Devices" },
  { id: "ota-053", stem: "An OTA is assessing grip strength using a Jamar dynamometer. Which handle position is standard for adults?", options: ["Position 1 (narrowest)", "Position 2", "Position 3 (widest)", "Position 5"], correctIndex: 1, rationale: "Position 2 on the Jamar dynamometer is the standard testing position for adult grip strength measurement, producing the highest grip force in most adults.", difficulty: 2, category: "Clinical Scenarios", topic: "Therapeutic Exercise" },
  { id: "ota-054", stem: "A client with quadriplegia needs to control environmental devices. What type of assistive technology should the OTA explore?", options: ["Standard light switches", "Environmental control units activated by sip-and-puff, voice, or head movement", "Manual remote controls", "Standard smartphone without modification"], correctIndex: 1, rationale: "Environmental control units (ECUs) can be activated by sip-and-puff, voice command, head movement, or eye gaze, enabling clients with quadriplegia to independently control lights, TV, phone, and other devices.", difficulty: 2, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "ota-055", stem: "During a pediatric OT session, a child becomes overwhelmed by tactile input and refuses to touch therapy materials. What is this response called?", options: ["Sensory seeking", "Tactile defensiveness", "Sensory registration deficit", "Normal sensory processing"], correctIndex: 1, rationale: "Tactile defensiveness is an aversive response to non-noxious touch stimuli. The child has a low neurological threshold for tactile input and actively avoids touch experiences.", difficulty: 2, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "ota-056", stem: "An OTA is treating a client who had an anterior approach hip replacement. Which movement is RESTRICTED?", options: ["Hip flexion to 90°", "Hip extension beyond neutral and external rotation", "Hip abduction", "Ankle dorsiflexion"], correctIndex: 1, rationale: "Anterior approach THR precautions restrict hip extension beyond neutral, external rotation, and combined movements that could cause anterior dislocation of the prosthesis.", difficulty: 3, category: "Safety", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-057", stem: "Which of the following activities uses the biomechanical frame of reference?", options: ["Cognitive retraining using computer exercises", "Progressive resistive exercise to increase grip strength after fracture", "Sensory integration therapy in a swing", "Group psychotherapy for stress management"], correctIndex: 1, rationale: "The biomechanical frame of reference addresses strength, ROM, and endurance through graded exercise and activity. PRE for grip strength directly targets biomechanical client factors.", difficulty: 2, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "ota-058", stem: "A client with hemiplegia is learning to dress. What is the general rule for donning a shirt?", options: ["Start with the unaffected arm first", "Start with the affected arm first", "Use both arms simultaneously", "Only use pullover shirts"], correctIndex: 1, rationale: "The rule for hemiplegic dressing: affected arm goes in first when donning (putting on). When doffing (removing), the unaffected arm comes out first. This prevents excessive strain on the affected side.", difficulty: 1, category: "Therapeutic Intervention", topic: "Rehabilitation Principles" },
  { id: "ota-059", stem: "An OTA is documenting a client's progress using SOAP note format. What belongs in the 'O' (Objective) section?", options: ["Client's complaints and reported pain level", "Measurable data such as ROM measurements, strength grades, and functional performance levels", "The OTA's treatment plan for next session", "The client's personal goals and values"], correctIndex: 1, rationale: "The Objective section contains measurable, observable data including ROM, strength, functional performance scores, and standardized assessment results — data that can be verified by any clinician.", difficulty: 1, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "ota-060", stem: "Which type of wheelchair cushion is MOST appropriate for a client at high risk for pressure injuries?", options: ["Standard foam cushion", "Gel or air-cell pressure-relieving cushion", "Flat wooden seat", "No cushion — just the sling seat"], correctIndex: 1, rationale: "Gel or air-cell cushions distribute pressure more evenly across the sitting surface, reducing peak pressures at bony prominences and lowering pressure injury risk.", difficulty: 2, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "ota-061", stem: "An OTA is working with a child with Down syndrome on feeding skills. The child has low muscle tone and tongue protrusion. Which intervention is appropriate?", options: ["Use a standard nipple without modification", "Provide jaw support, use a NUK brush for oral desensitization, and position in upright supported sitting", "Wait until the child is 5 years old to address feeding", "Feed the child only pureed foods indefinitely"], correctIndex: 1, rationale: "Children with Down syndrome benefit from jaw support during feeding, oral motor exercises for tongue control, proper upright positioning, and systematic texture progression.", difficulty: 3, category: "Therapeutic Intervention", topic: "Pediatric Rehabilitation" },
  { id: "ota-062", stem: "How often should a wheelchair-bound client perform weight-shift pressure relief?", options: ["Once per hour", "Every 15-30 minutes", "Only when skin redness appears", "Twice daily"], correctIndex: 1, rationale: "Weight shifts every 15-30 minutes redistribute pressure over bony prominences (ischial tuberosities) and prevent pressure injuries. Methods include forward lean, side lean, and push-ups.", difficulty: 1, category: "Safety", topic: "Patient Mobility Techniques" },
  { id: "ota-063", stem: "A client with carpal tunnel syndrome reports nighttime numbness and tingling in the thumb, index, and middle fingers. Which splint is typically prescribed?", options: ["Dynamic extension splint", "Wrist cock-up splint worn at night in neutral position", "Thumb spica splint", "Resting hand splint in full flexion"], correctIndex: 1, rationale: "A wrist splint in neutral position reduces pressure on the median nerve in the carpal tunnel during sleep. This is a first-line conservative treatment for carpal tunnel syndrome.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-064", stem: "An OTA is using Ayres Sensory Integration (ASI) therapy. What is a key principle of this approach?", options: ["The child follows a strict therapist-directed protocol without choice", "The child actively participates in selecting activities that provide the 'just-right challenge'", "Sensory input is avoided to prevent overstimulation", "Only visual and auditory input are addressed"], correctIndex: 1, rationale: "ASI therapy emphasizes active child participation, the 'just-right challenge' (matching activity demands to the child's abilities), and adaptive responses to meaningful sensory experiences.", difficulty: 3, category: "Therapeutic Intervention", topic: "Pediatric Rehabilitation" },
  { id: "ota-065", stem: "A client with a newly diagnosed stroke is unable to recognize objects by touch despite intact sensation. What is this deficit called?", options: ["Unilateral neglect", "Astereognosis", "Apraxia", "Aphasia"], correctIndex: 1, rationale: "Astereognosis is the inability to identify objects by touch despite intact sensory function. It results from damage to the sensory association cortex in the parietal lobe.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "ota-066", stem: "An OTA is grading a dressing activity for a client recovering from a brain injury. What does 'grading DOWN' mean?", options: ["Making the activity more complex and challenging", "Simplifying the activity by reducing steps, providing cues, or using easier clothing items", "Removing all assistance and expecting independence", "Changing to a completely different activity"], correctIndex: 1, rationale: "Grading down means simplifying the activity demands — reducing the number of steps, providing additional cues, using easier fasteners or clothing, or adding adaptive equipment.", difficulty: 1, category: "Therapeutic Intervention", topic: "Rehabilitation Principles" },
  { id: "ota-067", stem: "Which standardized test measures fine motor dexterity by timing how quickly a client places and removes 9 pegs from a pegboard?", options: ["Box and Block Test", "Nine-Hole Peg Test", "Jebsen-Taylor Hand Function Test", "Purdue Pegboard Test"], correctIndex: 1, rationale: "The Nine-Hole Peg Test measures fine motor dexterity by timing how quickly the client places and removes 9 pegs. Normal adult completion time is approximately 18-20 seconds.", difficulty: 1, category: "Clinical Scenarios", topic: "Therapeutic Exercise" },
  { id: "ota-068", stem: "A client with RA asks why they should avoid carrying heavy grocery bags by the handles. What is the BEST explanation?", options: ["It is too time-consuming", "Carrying by handles concentrates force on small finger joints; using forearms distributes load to larger joints", "There is no reason to avoid this activity", "Heavy grocery bags are too expensive"], correctIndex: 1, rationale: "Joint protection principles require using the largest joints possible. Carrying bags by handles stresses small finger joints; using forearms, carts, or bags with shoulder straps distributes the load.", difficulty: 2, category: "Patient Care Planning", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-069", stem: "An OTA is implementing a group OT session in a mental health setting. What is the OTA's PRIMARY role?", options: ["Providing individual psychotherapy to each group member", "Facilitating therapeutic group activities that address functional goals", "Prescribing psychiatric medications", "Conducting psychological testing"], correctIndex: 1, rationale: "In mental health settings, the OTA facilitates group activities that address functional goals such as coping skills, social interaction, stress management, and daily living skills.", difficulty: 2, category: "Therapeutic Intervention", topic: "Rehabilitation Principles" },
  { id: "ota-070", stem: "A client demonstrates difficulty sequencing the steps of making a sandwich despite understanding each individual step. What is this deficit?", options: ["Agnosia", "Aphasia", "Apraxia (ideational)", "Ataxia"], correctIndex: 2, rationale: "Ideational apraxia is the inability to plan and sequence multi-step motor tasks despite understanding the individual components. The client knows what to do but cannot organize the sequence.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "ota-071", stem: "An OTA is measuring a client's active shoulder flexion using a goniometer. The stationary arm is aligned with what landmark?", options: ["The lateral epicondyle of the humerus", "The midaxillary line of the trunk", "The olecranon process", "The acromion process"], correctIndex: 1, rationale: "For shoulder flexion goniometry, the axis is at the acromion, the stationary arm aligns with the midaxillary line of the trunk, and the moving arm aligns with the lateral midline of the humerus.", difficulty: 2, category: "Clinical Scenarios", topic: "Therapeutic Exercise" },
  { id: "ota-072", stem: "Which client would benefit MOST from a rocker knife?", options: ["A client with bilateral upper extremity strength", "A client with one functional upper extremity who needs to cut food independently", "A client with visual impairment only", "A client with hearing loss"], correctIndex: 1, rationale: "A rocker knife uses a rocking motion to cut food with one hand, making it ideal for clients with hemiplegia or any condition limiting them to one functional upper extremity.", difficulty: 1, category: "Therapeutic Intervention", topic: "Assistive Devices" },
  { id: "ota-073", stem: "A client is performing a stand-pivot transfer. What is the correct sequence?", options: ["Sit → Lock brakes → Stand → Pivot → Sit", "Stand → Move wheelchair → Sit → Lock brakes", "Lock brakes → Scoot forward → Stand → Pivot on stronger leg → Sit in controlled manner", "Jump from wheelchair to target surface"], correctIndex: 2, rationale: "Correct stand-pivot transfer: lock brakes, scoot forward to edge of seat, lean forward (nose over toes), push up to stand, pivot on the stronger leg, and sit in a controlled manner.", difficulty: 2, category: "Safety", topic: "Patient Mobility Techniques" },
  { id: "ota-074", stem: "What is the FIM score range, and what does a score of 1 represent?", options: ["0-10; score of 1 = minimal assist", "1-7; score of 1 = total assistance/dependent", "1-5; score of 1 = independent", "0-100; score of 1 = normal function"], correctIndex: 1, rationale: "FIM scores range from 1 (total assistance — client performs <25% of task) to 7 (complete independence). Each item measures the level of assistance required for functional tasks.", difficulty: 1, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-075", stem: "An OTA is treating a burn client with dorsal hand burns. Which splint position prevents contracture?", options: ["Wrist flexion, MCP extension, IP flexion (claw position)", "Wrist extension, MCP flexion 70-90°, IP extension (anti-deformity position)", "Full fist position", "Wrist and finger neutral"], correctIndex: 1, rationale: "Dorsal hand burns tend to cause MCP extension and IP flexion contractures (claw deformity). The anti-deformity splint positions wrist in extension, MCPs in flexion, and IPs in extension.", difficulty: 3, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-076", stem: "A child in early intervention (birth to age 3) receives OT services. Where should services be provided?", options: ["Only in outpatient clinic settings", "In the child's natural environment (home, daycare, community)", "Only in hospital-based pediatric units", "In a school-based therapy room"], correctIndex: 1, rationale: "IDEA Part C mandates that early intervention services (birth to 3) are provided in the child's natural environment — home, daycare, or community settings — not clinic-based.", difficulty: 2, category: "Patient Care Planning", topic: "Pediatric Rehabilitation" },
  { id: "ota-077", stem: "An OTA is using the Box and Block Test. What does this assessment measure?", options: ["Bilateral hand strength", "Unilateral gross manual dexterity by counting blocks transferred in 60 seconds", "Visual-perceptual processing", "Cognitive function"], correctIndex: 1, rationale: "The Box and Block Test measures unilateral gross manual dexterity by counting how many blocks the client transfers from one compartment to another in 60 seconds.", difficulty: 2, category: "Clinical Scenarios", topic: "Therapeutic Exercise" },
  { id: "ota-078", stem: "A client who uses a wheelchair reports redness over the ischial tuberosities. What should the OTA assess FIRST?", options: ["The client's diet and nutrition", "Wheelchair cushion type, sitting posture, and weight-shift frequency", "The color of the wheelchair upholstery", "The client's preferred seating position in the car"], correctIndex: 1, rationale: "Ischial redness indicates excessive pressure. The OTA should assess the wheelchair cushion (type and condition), sitting posture (pelvic alignment), and weight-shift compliance (frequency and effectiveness).", difficulty: 2, category: "Safety", topic: "Assistive Devices" },
  { id: "ota-079", stem: "Which intervention approach focuses on teaching a client to use remaining abilities and adaptive strategies to perform tasks they cannot do the typical way?", options: ["Remediation approach", "Compensatory/adaptive approach", "Preventive approach", "Health promotion approach"], correctIndex: 1, rationale: "The compensatory/adaptive approach teaches alternative methods, adaptive equipment use, and environmental modifications when underlying impairments cannot be fully remediated.", difficulty: 1, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "ota-080", stem: "An OTA is working with a client who has Parkinson's disease. Which functional difficulty is characteristic?", options: ["Excessive involuntary large movements", "Difficulty initiating movement (akinesia), shuffling gait, and micrographia", "Complete flaccid paralysis of all extremities", "Severe visual field loss"], correctIndex: 1, rationale: "Parkinson's disease is characterized by bradykinesia/akinesia (difficulty initiating movement), shuffling festinating gait, micrographia (small handwriting), and resting tremor.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "ota-081", stem: "An OTA needs to fabricate a thumb spica splint. What is the primary indication for this splint?", options: ["Wrist flexion contracture", "De Quervain's tenosynovitis or CMC arthritis — immobilizing the thumb", "Finger flexion contracture", "Elbow epicondylitis"], correctIndex: 1, rationale: "A thumb spica splint immobilizes the thumb CMC and MCP joints while leaving the wrist and fingers free. It is used for De Quervain's tenosynovitis, CMC osteoarthritis, and thumb fractures.", difficulty: 2, category: "Therapeutic Intervention", topic: "Assistive Devices" },
  { id: "ota-082", stem: "A client can perform a bed-to-wheelchair transfer with 60% of the effort. What assistance level is this?", options: ["Minimal assist (client performs 75%+)", "Moderate assist (client performs 50-74%)", "Maximal assist (client performs 25-49%)", "Supervised/standby"], correctIndex: 1, rationale: "Moderate assist means the client performs 50-74% of the task. At 60%, the client contributes more than half but less than 75% of the effort required.", difficulty: 1, category: "Patient Care Planning", topic: "Patient Mobility Techniques" },
  { id: "ota-083", stem: "An OTA is educating a caregiver in safe transfer techniques for a client with dementia. What is the MOST important instruction?", options: ["Transfer quickly to minimize confusion", "Use clear, simple verbal cues, maintain a consistent routine, and always lock wheelchair brakes", "Allow the client to direct the entire transfer independently", "Perform transfers only in the morning when the client is most confused"], correctIndex: 1, rationale: "For clients with dementia, consistent routines, clear simple cues, and safety precautions (locking brakes, proper positioning) reduce confusion and fall risk during transfers.", difficulty: 2, category: "Safety", topic: "Patient Mobility Techniques" },
  { id: "ota-084", stem: "Which developmental milestone is expected at approximately 6-8 months of age?", options: ["Independent walking", "Independent sitting", "Skipping and hopping", "Tying shoelaces"], correctIndex: 1, rationale: "Independent sitting typically develops at 6-8 months. This milestone requires adequate trunk control, righting reactions, and protective extension responses.", difficulty: 1, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "ota-085", stem: "An OTA is working with a client who has a flexor tendon repair. Why is it critical NOT to perform aggressive passive extension in early healing?", options: ["Extension is not functional for the hand", "Aggressive passive extension can rupture the healing tendon at the repair site", "Extension exercises are always unnecessary after surgery", "The client's insurance does not cover extension exercises"], correctIndex: 1, rationale: "Aggressive passive extension places tensile stress across the flexor tendon repair site. During early healing (first 3-4 weeks), this force can exceed the tendon's tensile strength, causing rupture.", difficulty: 3, category: "Safety", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-086", stem: "Which of the following is a characteristic of the sensory integration frame of reference?", options: ["Focus on conscious cognitive strategies", "Emphasis on neuroplasticity through controlled sensory experiences", "Treatment only in classroom settings", "Avoidance of all sensory stimulation"], correctIndex: 1, rationale: "The SI frame of reference uses controlled, meaningful sensory experiences to improve the brain's ability to process and integrate sensory information, relying on neuroplasticity.", difficulty: 2, category: "Patient Care Planning", topic: "Pediatric Rehabilitation" },
  { id: "ota-087", stem: "A client had a CVA and demonstrates inability to perform previously learned motor tasks despite intact motor function. What is this called?", options: ["Aphasia", "Agnosia", "Apraxia (ideomotor)", "Athetosis"], correctIndex: 2, rationale: "Ideomotor apraxia is the inability to perform previously learned motor tasks despite intact motor function and comprehension. The client understands the task but cannot execute it on command.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "ota-088", stem: "What is the recommended wearing schedule when initiating a new splint?", options: ["24 hours/day without removal for 2 weeks", "Gradual wearing schedule with skin checks every 2 hours initially", "Only during therapy sessions", "At night only without any daytime use"], correctIndex: 1, rationale: "New splints require a gradual wearing schedule with skin checks every 2 hours to identify pressure areas before skin breakdown occurs. Wearing time is increased as tolerance develops.", difficulty: 2, category: "Safety", topic: "Assistive Devices" },
  { id: "ota-089", stem: "An OTA is working with a client post-TBI who is at Rancho Level IV. What behavior characterizes this level?", options: ["No response to stimulation", "Confused and agitated — may exhibit aggressive or flight behavior", "Purposeful and appropriate in all activities", "Alert and oriented with normal cognitive function"], correctIndex: 1, rationale: "Rancho Level IV is 'confused-agitated.' The client may demonstrate bizarre behavior, aggression, confusion, and inability to cooperate with treatment. Safety is the primary concern.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "ota-090", stem: "A client with chronic obstructive pulmonary disease (COPD) experiences dyspnea during ADLs. Which OT intervention is appropriate?", options: ["Encourage the client to hold their breath during activities", "Teach pursed-lip breathing and energy conservation techniques during ADLs", "Advise the client to avoid all physical activity", "Prescribe supplemental oxygen without medical orders"], correctIndex: 1, rationale: "Pursed-lip breathing helps maintain airway patency and reduces air trapping. Combined with energy conservation techniques (pacing, prioritizing, positioning), the client can perform ADLs more effectively.", difficulty: 2, category: "Therapeutic Intervention", topic: "Rehabilitation Principles" },
  { id: "ota-091", stem: "An OTA is evaluating a client's home for accessibility. Which bathroom modification is MOST important for fall prevention?", options: ["Decorative bath mat", "Grab bars near toilet and shower/tub with non-slip strips", "Heated towel rack", "Larger mirror"], correctIndex: 1, rationale: "Grab bars near the toilet and in the shower/tub, combined with non-slip strips, are the most critical bathroom safety modifications to prevent falls in the most common fall location.", difficulty: 1, category: "Safety", topic: "Geriatric Rehabilitation" },
  { id: "ota-092", stem: "A client using a reacher to pick up objects dropped on the floor is using which OT intervention approach?", options: ["Remediation — restoring the ability to bend down", "Compensation — using adaptive equipment to bypass the limitation", "Prevention — stopping the objects from falling", "Health promotion — improving overall fitness"], correctIndex: 1, rationale: "Using a reacher is a compensatory/adaptive approach — the client uses adaptive equipment to perform a task they cannot do the typical way (bending to the floor).", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "ota-093", stem: "An OTA is helping a child with cerebral palsy work on self-feeding. The child has difficulty bringing the spoon to the mouth. Which adaptation would help?", options: ["Use a standard metal spoon without modification", "Provide a built-up, weighted spoon with a swivel feature and a non-slip mat under the plate", "Eliminate utensils entirely", "Use a fork instead of a spoon"], correctIndex: 1, rationale: "A built-up handle accommodates limited grasp, weighting dampens tremor/ataxia, a swivel feature keeps the spoon level despite limited wrist control, and a non-slip mat stabilizes the plate.", difficulty: 2, category: "Therapeutic Intervention", topic: "Pediatric Rehabilitation" },
  { id: "ota-094", stem: "What is the PRIMARY role of the OTA in the OT process?", options: ["Establish the diagnosis and prognosis", "Implement interventions directed by the supervising OT", "Independently evaluate and discharge clients", "Prescribe adaptive equipment without OT oversight"], correctIndex: 1, rationale: "The OTA's primary role is implementing interventions within the plan of care established by the supervising OT. The OT evaluates, establishes goals, and directs the plan of care.", difficulty: 1, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "ota-095", stem: "A client with left CVA damage is most likely to exhibit which type of deficit?", options: ["Left unilateral neglect", "Right-sided weakness and aphasia", "Left-sided weakness only", "Visual field cut on the left"], correctIndex: 1, rationale: "Left hemisphere stroke typically causes right-sided motor deficits (right hemiplegia) and language deficits (aphasia), as the left hemisphere is dominant for language in most people.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "ota-096", stem: "An OTA is setting up a client's electric wheelchair for the first time. What is the MOST important safety consideration?", options: ["Matching the wheelchair color to client preferences", "Ensuring the client can safely operate the controls and stop the chair in an emergency", "Setting the maximum speed as high as possible", "Removing all safety features for easier operation"], correctIndex: 1, rationale: "The most critical safety consideration is confirming the client can safely operate the controls, navigate obstacles, and stop the wheelchair in an emergency before independent use.", difficulty: 1, category: "Safety", topic: "Assistive Devices" },
  { id: "ota-097", stem: "A client receiving OT in a skilled nursing facility asks when they will be discharged. Who makes the discharge decision?", options: ["The OTA independently decides discharge", "The supervising OT makes the discharge recommendation based on goal achievement", "The client decides on their own", "The nursing staff determines OT discharge"], correctIndex: 1, rationale: "The supervising OT makes discharge recommendations based on goal achievement, functional status, and clinical reasoning. Discharge planning is outside the OTA's scope of practice.", difficulty: 2, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "ota-098", stem: "An OTA is using retrograde massage to manage hand edema. What is the correct direction of massage?", options: ["Proximal to distal (shoulder toward fingertips)", "Distal to proximal (fingertips toward shoulder)", "Circular motions only on the palm", "Random directions throughout the hand"], correctIndex: 1, rationale: "Retrograde massage moves fluid from distal to proximal (fingertips toward the heart), following the direction of venous and lymphatic drainage to reduce edema.", difficulty: 1, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "ota-099", stem: "A client with bilateral hand weakness needs to eat soup. Which adaptive equipment combination is BEST?", options: ["Standard bowl and spoon", "Built-up handled spoon with non-slip mat and bowl with a suction base", "Plate guard on a flat plate", "Fork and knife set"], correctIndex: 1, rationale: "A built-up spoon accommodates weak grasp, a non-slip mat prevents the bowl from sliding, and a suction base further stabilizes the bowl for one-handed or weak-grip scooping.", difficulty: 2, category: "Therapeutic Intervention", topic: "Assistive Devices" },
  { id: "ota-100", stem: "An OTA is facilitating a cooking group in a psychiatric setting. A client becomes increasingly agitated and throws a utensil. What is the FIRST priority?", options: ["Continue the group activity and ignore the behavior", "Ensure safety of all group members, calmly de-escalate, and remove the client if needed", "Physically restrain the client immediately", "Ask another client to manage the situation"], correctIndex: 1, rationale: "Safety is always the first priority. The OTA must ensure the safety of all group members, attempt calm de-escalation, remove the agitated client if necessary, and follow facility protocols.", difficulty: 2, category: "Safety", topic: "Rehabilitation Principles" },
  { id: "ota-201", stem: "An OTA is treating a client with lateral epicondylitis. Which activity modification should be recommended?", options: ["Increase gripping force during tasks", "Use tools with built-up handles and avoid repetitive wrist extension against resistance", "Perform aggressive stretching of wrist extensors under heavy load", "Apply heat before performing the aggravating activity without modifying technique"], correctIndex: 1, rationale: "Lateral epicondylitis involves inflammation of wrist extensor tendons at the lateral epicondyle. Built-up handles reduce grip force, and avoiding repetitive wrist extension decreases stress on the affected tendons.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-202", stem: "A client with a T12 SCI wants to dress the lower body independently. Which technique should the OTA train?", options: ["Standing to pull pants up over hips", "Supine or long-sitting lower body dressing using momentum and rolling techniques", "Sitting at edge of bed with legs dangling unsupported", "Kneeling position for lower body dressing"], correctIndex: 1, rationale: "T12 SCI clients have intact upper body function but lack lower extremity control. Supine or long-sitting dressing with log rolling and momentum allows independent lower body dressing without standing.", difficulty: 2, category: "Patient Care Planning", topic: "Neurological Rehabilitation" },
  { id: "ota-203", stem: "An OTA notices a client with diabetes has a small open wound on the dorsum of the hand that the client did not notice. What should the OTA do?", options: ["Ignore it since it is small", "Alert the supervising OT and nursing staff immediately due to impaired sensation and healing risk", "Apply essential oils to the wound", "Tell the client to monitor it at home"], correctIndex: 1, rationale: "Clients with diabetes often have impaired sensation and delayed wound healing. Even small wounds carry infection risk and must be reported to the supervising OT and nursing for proper wound care.", difficulty: 2, category: "Safety", topic: "Rehabilitation Principles" },
  { id: "ota-204", stem: "A client with early-stage multiple sclerosis reports fatigue that limits daily activities. Which OT strategy is MOST appropriate?", options: ["Encourage the client to push through fatigue to build endurance", "Teach energy conservation and work simplification techniques", "Recommend the client stop all activities", "Prescribe vigorous cardiovascular exercise"], correctIndex: 1, rationale: "MS-related fatigue is a primary symptom not relieved by pushing through. Energy conservation, work simplification, pacing, and activity modification are key OT strategies for managing MS fatigue.", difficulty: 2, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "ota-205", stem: "A 5-year-old child avoids playground equipment and becomes anxious when feet leave the ground. Which sensory system is likely involved?", options: ["Gustatory system", "Vestibular system — gravitational insecurity", "Olfactory system", "Interoceptive system"], correctIndex: 1, rationale: "Gravitational insecurity is a vestibular processing disorder where the child has an excessive fear response to movement and changes in head position, resulting in avoidance of playground equipment.", difficulty: 2, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "ota-206", stem: "An OTA is working with a client who has a flexor tendon repair at 6 weeks post-surgery. What exercise progression is appropriate?", options: ["Continue passive ROM only", "Begin gentle active ROM as cleared by the surgeon", "Start heavy resistive exercises immediately", "Discontinue all hand therapy"], correctIndex: 1, rationale: "At 6 weeks post flexor tendon repair, the tendon has sufficient healing strength to begin gentle active ROM. Heavy resistance is typically not introduced until 8-12 weeks post-surgery.", difficulty: 3, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-207", stem: "A client in an acute psychiatric unit refuses to participate in an OT group. What is the BEST initial response by the OTA?", options: ["Force the client to attend as it is prescribed", "Respect the client's autonomy, offer alternatives, and document the refusal", "Discharge the client from OT services immediately", "Report the client's behavior as non-compliant to the psychiatrist"], correctIndex: 1, rationale: "Clients have the right to refuse treatment. The OTA should respect autonomy, explore reasons for refusal, offer alternative activities, and document the interaction for the supervising OT.", difficulty: 2, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "ota-208", stem: "An OTA is training a client with C6 tetraplegia to use tenodesis grasp. What wrist movement enables this grasp pattern?", options: ["Wrist flexion opens the hand; wrist extension closes the hand", "Wrist extension creates passive finger flexion for grasp", "Ulnar deviation powers the grasp", "Pronation and supination control finger opening and closing"], correctIndex: 1, rationale: "Tenodesis grasp uses wrist extension to create passive finger flexion through tension in the long finger flexor tendons, allowing a functional grasp pattern without active finger muscles.", difficulty: 3, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "ota-209", stem: "During a dressing evaluation, a client with left neglect consistently ignores the left sleeve. Which compensatory strategy should the OTA teach?", options: ["Always start dressing with the right side first", "Anchor attention by placing a bright-colored marker on the left side and teach scanning left", "Dress only the right side and have a caregiver complete the left", "Use a mirror on the right side only"], correctIndex: 1, rationale: "Anchoring techniques using visual cues (bright tape, colored markers) on the neglected side combined with systematic visual scanning training help clients attend to the left side during dressing.", difficulty: 2, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "ota-210", stem: "A client with COPD is learning upper body dressing. Which positioning reduces dyspnea during the task?", options: ["Standing with arms overhead", "Seated with arms supported, using pursed-lip breathing and front-opening garments", "Lying flat in supine", "Bending forward at the waist with arms behind the back"], correctIndex: 1, rationale: "Seated positioning reduces oxygen demand, arm support decreases accessory muscle fatigue, pursed-lip breathing maintains airway patency, and front-opening garments reduce overhead reaching.", difficulty: 2, category: "Patient Care Planning", topic: "Geriatric Rehabilitation" },
  { id: "ota-211", stem: "An OTA is conducting a kitchen safety assessment. The client has poor standing balance. Which adaptation is the HIGHEST priority?", options: ["Reorganizing pantry items alphabetically", "Installing grab bars near the stove and recommending a perching stool for meal preparation", "Replacing all pots and pans with new ones", "Changing the kitchen wall color for better contrast"], correctIndex: 1, rationale: "Grab bars near the stove prevent falls during cooking, and a perching stool allows seated meal preparation, reducing fatigue and fall risk for clients with poor standing balance.", difficulty: 2, category: "Safety", topic: "Geriatric Rehabilitation" },
  { id: "ota-212", stem: "Which developmental milestone is expected at approximately 6 months of age?", options: ["Walking independently", "Sitting independently with hands free for play", "Using a mature pincer grasp", "Cutting with scissors"], correctIndex: 1, rationale: "Independent sitting with hands free typically develops around 6 months. Walking develops at 12-15 months, mature pincer grasp at 10-12 months, and scissor skills at 3-4 years.", difficulty: 1, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "ota-213", stem: "A client with a radial nerve injury at the spiral groove presents with wrist drop. Which splint should the OTA fabricate?", options: ["Resting hand splint in intrinsic plus position", "Dynamic wrist extension splint to support the wrist and allow functional hand use", "Ulnar gutter splint", "Thumb spica splint"], correctIndex: 1, rationale: "Radial nerve injury causes wrist drop due to paralyzed wrist extensors. A dynamic wrist extension splint supports the wrist in functional position while allowing tendon gliding and hand function.", difficulty: 3, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-214", stem: "An OTA is working with a client who has severe burns on both hands. What is the anti-deformity position for the burned hand?", options: ["Wrist flexion, MCP extension, IP flexion, thumb adduction", "Wrist extension, MCP flexion 70-90°, IP extension, thumb abduction and extension", "Fist position with all joints fully flexed", "Wrist neutral with all fingers extended and adducted"], correctIndex: 1, rationale: "The anti-deformity position for burned hands counteracts the typical contracture pattern: wrist extension, MCP flexion, IP extension, and thumb abduction to maintain web space and joint mobility.", difficulty: 3, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-215", stem: "A client post-stroke is working on meal preparation. They can follow 2-step directions but get confused with 3 or more steps. How should the OTA grade the activity?", options: ["Provide all directions at once to challenge the client", "Break the recipe into 2-step sequences with visual cue cards", "Choose a different activity entirely", "Have the client memorize the entire recipe before starting"], correctIndex: 1, rationale: "Grading the cognitive demands to match the client's current ability (2-step directions) with visual cue cards supports successful task completion and can be progressively upgraded.", difficulty: 2, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "ota-216", stem: "An OTA is documenting a client's progress using SOAP note format. Which statement belongs in the 'O' (Objective) section?", options: ["Client reports feeling better today", "Client completed 10 repetitions of shoulder flexion to 120° with moderate assist", "Client will improve UE ROM to within functional limits in 4 weeks", "Continue current treatment plan 3x/week"], correctIndex: 1, rationale: "The Objective section contains measurable, observable data collected by the clinician — ROM measurements, repetition counts, and assistance levels are objective findings.", difficulty: 1, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "ota-217", stem: "A client recovering from Guillain-Barré syndrome is in the recovery phase. Which intervention approach is MOST appropriate?", options: ["Aggressive resistive exercise to maximum fatigue", "Graded activity progressing from gentle AROM to light resistance, monitoring for overwork weakness", "Complete bedrest until full recovery", "Passive ROM only for the duration of recovery"], correctIndex: 1, rationale: "GBS recovery requires careful activity grading to avoid overwork weakness (paradoxical weakening from overexertion). Progressive activity from gentle AROM to light resistance with fatigue monitoring is appropriate.", difficulty: 3, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "ota-218", stem: "During a home visit, an OTA observes that a client's bathroom has no grab bars, a high tub wall, and a slippery floor. What is the priority recommendation?", options: ["Install decorative towel racks for visual appeal", "Install grab bars near the tub and toilet, add a tub bench, and use non-slip mats", "Recommend the client avoid bathing", "Suggest the client move to a facility"], correctIndex: 1, rationale: "Bathroom falls are a leading cause of injury. Grab bars provide support during transfers, a tub bench eliminates stepping over the high tub wall, and non-slip mats reduce slip risk.", difficulty: 1, category: "Safety", topic: "Geriatric Rehabilitation" },
  { id: "ota-219", stem: "An OTA is treating a client with de Quervain's tenosynovitis. Which tendon compartment is affected?", options: ["Second dorsal compartment (ECRL, ECRB)", "First dorsal compartment (APL, EPB)", "Third dorsal compartment (EPL)", "Fourth dorsal compartment (EDC, EIP)"], correctIndex: 1, rationale: "De Quervain's tenosynovitis affects the first dorsal compartment containing the abductor pollicis longus (APL) and extensor pollicis brevis (EPB) tendons at the radial styloid.", difficulty: 3, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-220", stem: "A child with autism spectrum disorder becomes overwhelmed during a classroom art activity. Which sensory strategy should the OTA recommend to the teacher?", options: ["Insist the child complete the activity without modification", "Provide a quiet corner with reduced stimulation where the child can self-regulate before returning", "Remove art activities from the curriculum entirely", "Have the child sit in the center of the classroom for more social exposure"], correctIndex: 1, rationale: "A designated quiet space with reduced sensory input allows the child to self-regulate and return to the activity when ready. This supports participation without overwhelming the child's sensory system.", difficulty: 2, category: "Therapeutic Intervention", topic: "Pediatric Rehabilitation" },
  { id: "ota-221", stem: "A client with a recent hip fracture fixation is weight-bearing as tolerated. Which bathing adaptation is MOST important?", options: ["Use a standard bathtub without modifications", "Use a shower chair and handheld shower head to avoid standing fatigue and fall risk", "Take sponge baths only for 6 months", "Bathe in cold water to reduce inflammation"], correctIndex: 1, rationale: "A shower chair eliminates prolonged standing and fall risk, while a handheld shower head allows the client to bathe while seated, maintaining hip precautions and weight-bearing status.", difficulty: 1, category: "Patient Care Planning", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-222", stem: "An OTA is using the Cognitive Disabilities Model (Allen) with a client at ACL 3. What type of task can this client perform?", options: ["Complex multi-step meal preparation", "Repetitive manual actions that are familiar and guided by tactile cues", "Independent community mobility and money management", "Abstract reasoning and problem-solving tasks"], correctIndex: 1, rationale: "ACL 3 (manual actions) indicates the client can perform repetitive, familiar motor tasks guided by tactile cues but cannot attend to visual cues or problem-solve. Activities must be simple and hands-on.", difficulty: 3, category: "Clinical Scenarios", topic: "Geriatric Rehabilitation" },
  { id: "ota-223", stem: "A client with an upper extremity amputation is learning to use a body-powered prosthesis. What motion operates the terminal device?", options: ["Wrist rotation", "Glenohumeral flexion and scapular abduction via a cable-control system", "Elbow extension only", "Contralateral hand activation"], correctIndex: 1, rationale: "Body-powered prostheses use a cable system activated by glenohumeral flexion and scapular abduction (biscapular abduction) to operate the terminal device for grasp and release.", difficulty: 3, category: "Therapeutic Intervention", topic: "Assistive Devices" },
  { id: "ota-224", stem: "An OTA is leading a life skills group for adolescents with emotional disturbance. Which group format is MOST appropriate?", options: ["Parallel group — each member works independently", "Project group — members share materials but work on separate tasks", "Cooperative group — members work together with shared responsibility for outcomes", "Evaluative group — members only observe and provide feedback"], correctIndex: 2, rationale: "A cooperative group for adolescents with emotional disturbance promotes social skills, shared responsibility, peer interaction, and emotional regulation within a structured therapeutic context.", difficulty: 2, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "ota-225", stem: "A client with a median nerve injury at the wrist cannot oppose the thumb. Which functional grasp is MOST affected?", options: ["Hook grasp", "Lateral (key) pinch", "Tip-to-tip pinch", "Cylindrical grasp"], correctIndex: 2, rationale: "Median nerve injury at the wrist affects thenar muscles responsible for thumb opposition. Tip-to-tip pinch requires opposition and is most affected; lateral pinch uses ulnar-innervated adductor pollicis.", difficulty: 3, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-226", stem: "An OTA is providing caregiver training for a family member who will assist a client with moderate dementia at home. What should be emphasized?", options: ["Complex verbal instructions for each ADL step", "Consistent routines, simple one-step cues, and structured environment with visual supports", "Allowing the client complete independence without supervision", "Teaching the client new technology-based reminder systems"], correctIndex: 1, rationale: "Clients with moderate dementia benefit from consistent routines, simple cues, and structured environments. Caregivers should maintain predictability and use visual supports to reduce confusion.", difficulty: 2, category: "Patient Care Planning", topic: "Geriatric Rehabilitation" },
  { id: "ota-227", stem: "During a functional assessment, an OTA notes a client requires verbal cues for 50% of the steps during grooming. What assistance level is this?", options: ["Independent", "Supervision", "Moderate assistance", "Maximum assistance"], correctIndex: 2, rationale: "Moderate assistance is defined as the client requiring help with 25-50% or more of task steps. Verbal cueing for 50% of grooming steps indicates moderate assistance level.", difficulty: 2, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-228", stem: "A client with carpal tunnel syndrome reports numbness in the thumb, index, and middle fingers. Which nerve is compressed?", options: ["Ulnar nerve", "Radial nerve", "Median nerve", "Musculocutaneous nerve"], correctIndex: 2, rationale: "Carpal tunnel syndrome involves compression of the median nerve at the carpal tunnel, causing numbness and tingling in the median nerve distribution: thumb, index, middle, and radial half of ring finger.", difficulty: 1, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-229", stem: "An OTA is using graded motor imagery with a client who has complex regional pain syndrome. What is the correct sequence?", options: ["Mirror therapy → laterality recognition → mental imagery", "Laterality recognition → motor imagery → mirror therapy", "Mirror therapy only without any preparatory steps", "Resistive exercise → stretching → mirror therapy"], correctIndex: 1, rationale: "Graded motor imagery follows a specific sequence: laterality recognition (left/right discrimination), then explicit motor imagery (imagining movement), then mirror therapy, progressively activating cortical motor areas.", difficulty: 3, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-230", stem: "A 7-year-old child has difficulty copying shapes from the board to paper. Which visual perceptual skill is challenged?", options: ["Figure-ground perception", "Visual motor integration", "Depth perception", "Color discrimination"], correctIndex: 1, rationale: "Copying shapes from a board to paper requires visual motor integration — the coordination of visual perception with fine motor output. Deficits result in poor copying, handwriting, and drawing.", difficulty: 2, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "ota-231", stem: "An OTA is positioning a client in a wheelchair to prevent pressure ulcers. How often should weight shifts be performed?", options: ["Once every 2 hours", "Every 15-30 minutes for at least 15-30 seconds", "Only when the client feels discomfort", "Once at the beginning and end of the day"], correctIndex: 1, rationale: "Wheelchair-bound clients should perform weight shifts every 15-30 minutes to redistribute pressure over bony prominences and prevent pressure ulcer development. Methods include forward lean, lateral lean, and push-ups.", difficulty: 1, category: "Safety", topic: "Patient Mobility Techniques" },
  { id: "ota-232", stem: "A client with schizophrenia has flat affect and poor motivation for self-care. Which OT approach is BEST?", options: ["Confrontational approach about hygiene deficits", "Structured routine with achievable goals, positive reinforcement, and graded task demands", "Leaving the client alone to develop intrinsic motivation", "Complex multi-step grooming routines to stimulate cognition"], correctIndex: 1, rationale: "Negative symptoms of schizophrenia respond best to structured routines, achievable goals, positive reinforcement, and graded activities that build confidence and participation gradually.", difficulty: 2, category: "Therapeutic Intervention", topic: "Rehabilitation Principles" },
  { id: "ota-233", stem: "An OTA is fabricating a thumb spica splint for a client with gamekeeper's thumb (UCL injury). What position should the thumb be in?", options: ["Full thumb extension and adduction", "Thumb in slight flexion and abduction to protect the UCL", "Maximum opposition", "Full thumb radial abduction"], correctIndex: 1, rationale: "Gamekeeper's thumb (UCL injury of the MCP joint) requires immobilization with the thumb in slight flexion and abduction to protect the healing ulnar collateral ligament.", difficulty: 3, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-234", stem: "A client with myasthenia gravis reports increasing weakness during afternoon activities. How should the OTA schedule treatment sessions?", options: ["Schedule all sessions in the late afternoon to challenge endurance", "Schedule sessions in the morning when the client has the most strength, and use energy conservation", "Schedule sessions randomly throughout the day", "Double session length to accomplish more per visit"], correctIndex: 1, rationale: "Myasthenia gravis causes progressive muscle weakness with sustained activity. Scheduling sessions when the client is strongest (typically morning) and incorporating energy conservation maximizes function.", difficulty: 2, category: "Patient Care Planning", topic: "Neurological Rehabilitation" },
  { id: "ota-235", stem: "Which type of grasp is used when holding a key to unlock a door?", options: ["Spherical grasp", "Lateral (key) pinch", "Palmar prehension (3-jaw chuck)", "Hook grasp"], correctIndex: 1, rationale: "Lateral pinch (key pinch) involves the pad of the thumb pressing against the lateral (radial) side of the index finger, used for holding keys, cards, and flat objects.", difficulty: 1, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-236", stem: "An OTA is providing intervention for a client with executive function deficits after traumatic brain injury. Which strategy is MOST effective?", options: ["Expecting the client to self-organize naturally over time", "Using external aids (checklists, planners, alarms) and teaching metacognitive strategies for self-monitoring", "Removing all structure so the client must adapt independently", "Limiting all activities to passive participation"], correctIndex: 1, rationale: "Executive function deficits after TBI benefit from external organizational aids and metacognitive strategy training to support planning, initiation, sequencing, and self-monitoring of daily activities.", difficulty: 2, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "ota-237", stem: "A client with rheumatoid arthritis has swan-neck deformity of the ring finger. What does this deformity look like?", options: ["DIP hyperextension with PIP flexion", "PIP hyperextension with DIP flexion", "MCP ulnar deviation", "Boutonniere deformity"], correctIndex: 1, rationale: "Swan-neck deformity consists of PIP hyperextension and DIP flexion, caused by volar plate laxity and intrinsic muscle imbalance commonly seen in rheumatoid arthritis.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-238", stem: "An OTA is treating a child with developmental coordination disorder (DCD). Which activity is BEST to improve bilateral coordination?", options: ["Single-hand coloring", "Catching a large ball with both hands, progressing to smaller balls", "Watching videos about coordination", "Verbal instruction without motor practice"], correctIndex: 1, rationale: "Bilateral coordination activities like ball catching with progression from large to small targets provide graded motor challenges that directly address the bilateral coordination deficits in DCD.", difficulty: 2, category: "Therapeutic Intervention", topic: "Pediatric Rehabilitation" },
  { id: "ota-239", stem: "A client with a hip arthroplasty (posterior approach) needs to get dressed. Which dressing sequence should the OTA teach?", options: ["Dress the unaffected leg first, then the affected leg", "Dress the affected leg first while maintaining hip precautions using a reacher and dressing stick", "Stand to pull up pants without any assistive devices", "Bend forward past 90° to reach the feet"], correctIndex: 1, rationale: "After posterior hip arthroplasty, the affected leg is dressed first using assistive devices (reacher, dressing stick, long-handled shoe horn) to maintain precautions: no hip flexion >90°, no internal rotation, no adduction.", difficulty: 2, category: "Patient Care Planning", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-240", stem: "An OTA observes that a client with Parkinson's disease has micrographia. What does this mean?", options: ["The client writes in abnormally large letters", "The client's handwriting becomes progressively smaller and cramped", "The client cannot hold a pen", "The client writes only with the non-dominant hand"], correctIndex: 1, rationale: "Micrographia is a common Parkinson's symptom where handwriting becomes progressively smaller, lighter, and more cramped due to bradykinesia and reduced motor amplitude.", difficulty: 1, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "ota-241", stem: "A client with low vision needs to manage medications at home. Which adaptation should the OTA recommend?", options: ["Use standard prescription labels without modification", "Use large-print labels, a weekly pill organizer, and high-contrast markers on medication bottles", "Have the client memorize all medication names by feel", "Eliminate all medications that are difficult to identify"], correctIndex: 1, rationale: "Large-print labels, pill organizers, and high-contrast markers compensate for low vision while supporting safe, independent medication management at home.", difficulty: 1, category: "Patient Care Planning", topic: "Geriatric Rehabilitation" },
  { id: "ota-242", stem: "An OTA is treating a client with trigger finger. Which conservative intervention is appropriate before considering surgery?", options: ["Aggressive passive stretching of the affected finger", "Splinting the MCP joint in slight flexion (0-15°) to prevent triggering, combined with tendon gliding exercises", "Immediate surgical release without conservative trial", "Heavy resistive grip exercises"], correctIndex: 1, rationale: "Conservative treatment of trigger finger includes MCP blocking splints to prevent full flexion (which causes triggering), tendon gliding exercises, and activity modification to reduce repetitive gripping.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-243", stem: "A client with an anterior approach total hip replacement has different precautions than a posterior approach. What should be AVOIDED?", options: ["Hip flexion to 90°", "Hip extension and external rotation", "Seated activities", "Ankle pumps in sitting"], correctIndex: 1, rationale: "Anterior approach hip replacement precautions differ from posterior: avoid hip extension combined with external rotation, as this risks anterior dislocation. Hip flexion restrictions are less stringent.", difficulty: 3, category: "Safety", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-244", stem: "An OTA is working with a child who has difficulty with handwriting legibility. Which foundational skill should be assessed FIRST?", options: ["Reading comprehension", "In-hand manipulation, grasp pattern, and visual motor integration", "Verbal communication skills", "Mathematical reasoning"], correctIndex: 1, rationale: "Handwriting legibility depends on foundational skills: in-hand manipulation (pencil control), grasp pattern (efficient pencil hold), and visual motor integration (translating visual input to motor output).", difficulty: 2, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "ota-245", stem: "A client post-stroke demonstrates ideational apraxia. How does this present during ADL performance?", options: ["The client cannot initiate movement but knows the sequence", "The client cannot conceptualize the correct sequence of steps needed to complete a task", "The client has difficulty with fine motor dexterity only", "The client cannot see objects on the affected side"], correctIndex: 1, rationale: "Ideational apraxia is the inability to conceptualize and sequence the steps of a multi-step task. The client may use objects incorrectly (e.g., trying to brush hair with a toothbrush) or perform steps out of order.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "ota-246", stem: "An OTA is using fluidotherapy for a client with hand stiffness. What is the treatment medium and primary therapeutic effect?", options: ["Water jets that massage the hand", "Cellulose particles suspended in warm air providing dry heat and desensitization", "Ultrasound gel applied to the hand", "Cold gel packs wrapped around the hand"], correctIndex: 1, rationale: "Fluidotherapy uses cellulose particles circulated in warm dry air (118-125°F) to provide superficial dry heat, desensitization, and active exercise opportunity simultaneously.", difficulty: 2, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "ota-247", stem: "A client with a colostomy bag wants to return to community activities but is embarrassed. Which OT approach addresses this barrier?", options: ["Avoid discussing the colostomy entirely", "Address body image concerns, practice bag management, and plan community integration with strategies for confidence", "Tell the client they should not be embarrassed", "Recommend the client stay home until the colostomy is reversed"], correctIndex: 1, rationale: "OT addresses psychosocial aspects of disability including body image. Teaching independent bag management, discussing concerns, and gradual community integration build confidence and participation.", difficulty: 2, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "ota-248", stem: "An OTA is assessing a client's home for wheelchair accessibility. What is the minimum recommended doorway width for standard wheelchair access?", options: ["24 inches", "32 inches", "36 inches", "48 inches"], correctIndex: 1, rationale: "The ADA recommends a minimum clear doorway width of 32 inches for standard wheelchair passage. Wider doorways (36 inches) are preferred for easier maneuvering and power wheelchair access.", difficulty: 1, category: "Safety", topic: "Assistive Devices" },
  { id: "ota-249", stem: "A client with bilateral upper extremity weakness due to ALS is having difficulty eating. Which assistive technology should the OTA consider?", options: ["Standard utensils with no modifications", "Mobile arm supports (balanced forearm orthoses) and lightweight adapted utensils", "Bilateral upper extremity prostheses", "IV feeding only"], correctIndex: 1, rationale: "Mobile arm supports (BFOs) compensate for proximal weakness by supporting the forearm against gravity, allowing the client to bring utensils to the mouth using minimal residual strength.", difficulty: 2, category: "Therapeutic Intervention", topic: "Assistive Devices" },
  { id: "ota-250", stem: "An OTA observes a child using a whole-hand (palmar) grasp on crayons at age 5. What does this indicate?", options: ["Age-appropriate grasp development", "Delayed grasp development — a dynamic tripod grasp is expected by this age", "Superior fine motor skills", "Normal grasp that requires no intervention"], correctIndex: 1, rationale: "By age 5, children should demonstrate a dynamic tripod grasp. Persistent palmar grasp at this age indicates delayed fine motor development requiring assessment and intervention.", difficulty: 2, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "ota-251", stem: "A client with chronic pain demonstrates fear-avoidance behavior. Which OT approach is evidence-based?", options: ["Complete activity restriction to prevent pain", "Graded activity exposure combined with pain neuroscience education and self-management strategies", "Ignoring pain reports and pushing maximum activity", "Medicating before every activity"], correctIndex: 1, rationale: "Fear-avoidance is addressed through graded exposure to feared activities, pain neuroscience education to reduce catastrophizing, and self-management strategies to build self-efficacy.", difficulty: 2, category: "Therapeutic Intervention", topic: "Rehabilitation Principles" },
  { id: "ota-252", stem: "During morning ADLs, a client with right hemiplegia has difficulty stabilizing a toothpaste tube while opening it. What is the BEST compensatory strategy?", options: ["Have the caregiver always open the toothpaste", "Use a suction cup toothpaste holder or tube squeezer mounted to the counter for one-handed management", "Switch to mouthwash only", "Use teeth to open the tube"], correctIndex: 1, rationale: "Suction-based stabilizers and adapted tube squeezers enable one-handed toothpaste management for clients with hemiplegia, promoting independence in oral hygiene.", difficulty: 1, category: "Therapeutic Intervention", topic: "Assistive Devices" },
  { id: "ota-253", stem: "An OTA is treating a premature infant in the NICU. Which intervention principle is MOST important?", options: ["Provide maximum sensory stimulation to promote development", "Monitor physiological stress signs and provide gentle, graded sensory input based on infant state", "Complete all therapy goals regardless of infant state", "Use the same intervention protocol for all premature infants"], correctIndex: 1, rationale: "NICU intervention requires monitoring physiological stress signs (desaturation, color changes, behavioral cues) and providing individualized, graded sensory input aligned with the infant's current state and tolerance.", difficulty: 3, category: "Safety", topic: "Pediatric Rehabilitation" },
  { id: "ota-254", stem: "A client with cubital tunnel syndrome reports numbness in the ring and little fingers. Which nerve is compressed?", options: ["Median nerve", "Radial nerve", "Ulnar nerve", "Musculocutaneous nerve"], correctIndex: 2, rationale: "Cubital tunnel syndrome involves compression of the ulnar nerve at the elbow, causing numbness and tingling in the ulnar nerve distribution: little finger and ulnar half of the ring finger.", difficulty: 1, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-255", stem: "An OTA is teaching a client with cognitive impairments to use a smartphone for daily task reminders. What is this type of intervention called?", options: ["Remediation of cognitive deficits", "Assistive technology as a cognitive prosthetic", "Prevention of cognitive decline", "Health promotion"], correctIndex: 1, rationale: "Using a smartphone as a reminder system is an example of assistive technology functioning as a cognitive prosthetic — an external device that compensates for cognitive limitations.", difficulty: 2, category: "Therapeutic Intervention", topic: "Assistive Devices" },
  { id: "ota-256", stem: "A client with a stage II pressure ulcer on the sacrum is positioned in a wheelchair. What seat cushion should be recommended?", options: ["Standard foam cushion", "Pressure-relieving cushion (gel, air, or alternating pressure) with off-loading of the sacral area", "Hard wooden seat for posture support", "No cushion is needed if the client shifts weight regularly"], correctIndex: 1, rationale: "Stage II pressure ulcers require pressure-relieving cushions that distribute weight and off-load the sacral area. Gel, air, or alternating pressure cushions reduce interface pressure below capillary closing pressure.", difficulty: 2, category: "Safety", topic: "Patient Mobility Techniques" },
  { id: "ota-257", stem: "An OTA is evaluating a client's pinch strength using a pinch gauge. Which pinch type typically produces the STRONGEST measurement?", options: ["Tip-to-tip pinch", "Lateral (key) pinch", "Three-jaw chuck (palmar) pinch", "All pinch types produce equal force"], correctIndex: 1, rationale: "Lateral (key) pinch typically produces the strongest pinch force because it uses the powerful adductor pollicis muscle and provides a broader contact area between thumb and index finger.", difficulty: 2, category: "Clinical Scenarios", topic: "Therapeutic Exercise" },
  { id: "ota-258", stem: "A client with bipolar disorder in a manic phase wants to participate in OT. Which activity is MOST therapeutically appropriate?", options: ["Competitive group sport with high stimulation", "A calming, repetitive, structured individual activity such as simple beading or folding", "An open-ended creative art project with no boundaries", "A debate group to channel high energy"], correctIndex: 1, rationale: "During manic episodes, clients benefit from calming, structured, repetitive activities that channel energy without increasing stimulation. Competitive or open-ended activities may escalate arousal.", difficulty: 2, category: "Therapeutic Intervention", topic: "Rehabilitation Principles" },
  { id: "ota-259", stem: "An OTA is performing scar management after a hand burn. Which techniques are evidence-based for scar remodeling?", options: ["Leave the scar untreated for natural resolution", "Scar massage, silicone gel sheeting, compression garments, and custom pressure splints", "Apply ice to the scar three times daily", "Expose the scar to direct sunlight for vitamin D"], correctIndex: 1, rationale: "Evidence-based scar management includes deep friction scar massage to mobilize collagen, silicone products to hydrate and flatten scars, and compression/pressure to reduce hypertrophic scarring.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-260", stem: "A child with Down syndrome has hypotonia and ligamentous laxity. Which precaution should the OTA take during treatment?", options: ["Apply maximum resistance to strengthen muscles", "Avoid hyperextension of joints and be cautious with cervical spine due to risk of atlantoaxial instability", "Encourage maximal stretching of all joints", "Ignore joint laxity as it is not clinically significant"], correctIndex: 1, rationale: "Children with Down syndrome have ligamentous laxity and are at risk for atlantoaxial instability. The OTA must avoid hyperextension of joints and take cervical spine precautions during all activities.", difficulty: 2, category: "Safety", topic: "Pediatric Rehabilitation" },
  { id: "ota-261", stem: "An OTA is training a client to use one-handed techniques for shoe tying. Which method is appropriate?", options: ["Standard bow-tying method", "One-handed shoe tying technique using loops and friction, or elastic laces as an alternative", "Velcro shoes only", "Always requiring caregiver assistance"], correctIndex: 1, rationale: "One-handed shoe tying techniques (loop method) or adaptive alternatives (elastic laces, lock laces) enable independence. Multiple options should be presented based on client preference and dexterity.", difficulty: 1, category: "Therapeutic Intervention", topic: "Assistive Devices" },
  { id: "ota-262", stem: "A client with dementia is in the late stage of the disease. What type of sensory-based intervention is MOST appropriate?", options: ["Complex problem-solving activities", "Gentle multisensory stimulation (Snamezelen approach) with calming music, textures, and aromatherapy", "Intensive cognitive retraining programs", "Competitive group activities"], correctIndex: 1, rationale: "Late-stage dementia clients benefit from multisensory stimulation that provides comfort and engagement without cognitive demands. Snoezelen environments offer controlled sensory experiences.", difficulty: 2, category: "Patient Care Planning", topic: "Geriatric Rehabilitation" },
  { id: "ota-263", stem: "An OTA is measuring grip strength using a Jamar dynamometer. Which handle position is standard for testing?", options: ["First (narrowest) position", "Second position", "Fifth (widest) position", "Any position the client prefers"], correctIndex: 1, rationale: "The second handle position of the Jamar dynamometer is the standard testing position and typically produces the highest grip force reading across populations.", difficulty: 1, category: "Clinical Scenarios", topic: "Therapeutic Exercise" },
  { id: "ota-264", stem: "A client recovering from a traumatic brain injury demonstrates confabulation. What does this mean?", options: ["The client is intentionally lying", "The client fabricates stories to fill memory gaps without awareness that they are false", "The client has expressive aphasia", "The client is experiencing visual hallucinations"], correctIndex: 1, rationale: "Confabulation is the unintentional production of false memories or stories to fill gaps in memory. The client genuinely believes the fabricated information is true — it is not deliberate deception.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "ota-265", stem: "An OTA is adapting a computer workstation for a client with C5 tetraplegia. Which input method should be considered?", options: ["Standard keyboard and mouse", "Voice recognition software, head/mouth pointer, or sip-and-puff systems", "Touch typing training without adaptation", "Handwriting recognition tablet"], correctIndex: 1, rationale: "C5 tetraplegia limits hand function. Alternative computer input methods (voice recognition, head/mouth stick, sip-and-puff) bypass the need for fine motor control and enable computer access.", difficulty: 2, category: "Therapeutic Intervention", topic: "Assistive Devices" },
  { id: "ota-266", stem: "A client has a Boutonniere deformity of the index finger. What is the characteristic position of this deformity?", options: ["PIP hyperextension with DIP flexion", "PIP flexion with DIP hyperextension", "MCP hyperextension with PIP and DIP flexion", "All joints in full extension"], correctIndex: 1, rationale: "Boutonniere deformity presents as PIP flexion and DIP hyperextension, caused by disruption of the central slip of the extensor tendon at the PIP joint.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-267", stem: "An OTA is conducting a group session for clients with depression. Which therapeutic factor of group therapy is MOST beneficial?", options: ["Competition among group members", "Universality — realizing others share similar experiences reduces isolation", "Individual attention from the therapist only", "Physical exercise competition"], correctIndex: 1, rationale: "Universality (Yalom's therapeutic factor) helps clients with depression realize they are not alone in their struggles. This shared experience reduces isolation and fosters hope through peer connection.", difficulty: 2, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "ota-268", stem: "A client recovering from a rotator cuff repair is 8 weeks post-surgery. The surgeon clears active ROM. Which progression is appropriate?", options: ["Immediately begin heavy resistance training", "Start with gravity-eliminated active ROM and progress to against-gravity active ROM", "Continue passive ROM only for another 6 weeks", "Begin overhead throwing exercises"], correctIndex: 1, rationale: "At 8 weeks post-rotator cuff repair with AROM clearance, begin with gravity-eliminated positions and progress to against-gravity active ROM. Resistance is typically not introduced until 12+ weeks.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-269", stem: "An OTA notices a client using heavy joint compression during writing (pressing hard on paper). This behavior is characteristic of which sensory processing pattern?", options: ["Sensory avoiding", "Sensory sensitivity", "Sensory seeking — seeking proprioceptive input", "Low registration"], correctIndex: 2, rationale: "Heavy joint compression and excessive pressure during tasks indicate sensory seeking behavior, specifically proprioceptive seeking. The client craves deep pressure and heavy work to meet their sensory needs.", difficulty: 2, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "ota-270", stem: "A client with a total knee replacement needs to get in and out of a car. What technique should the OTA teach?", options: ["Jump into the car seat quickly", "Back up to the seat, sit down first, then pivot and lift the operated leg into the car using hands or a leg lifter", "Step directly into the car with the operated leg first", "Avoid car travel for 6 months"], correctIndex: 1, rationale: "After TKR, the client backs up to the car seat, sits down maintaining knee precautions, then pivots and lifts the operated leg into the car. A leg lifter strap may assist with leg clearance.", difficulty: 1, category: "Patient Care Planning", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-271", stem: "An OTA is treating a client with dysphagia. What should the OTA do if the client coughs repeatedly during eating?", options: ["Encourage the client to drink water quickly to clear the food", "Stop the meal, report to the supervising OT and speech-language pathologist, and ensure the client is positioned upright", "Continue the meal at a slower pace", "Lay the client flat to assist with swallowing"], correctIndex: 1, rationale: "Repeated coughing during eating suggests aspiration risk. The OTA must stop the meal, position the client upright, and immediately report to the supervising OT and SLP for swallowing reassessment.", difficulty: 2, category: "Safety", topic: "Geriatric Rehabilitation" },
  { id: "ota-272", stem: "A client with ulnar nerve palsy presents with clawing of the ring and little fingers. Which splint addresses this deformity?", options: ["Wrist cock-up splint", "MCP blocking splint (anti-claw splint) to prevent MCP hyperextension of the ring and little fingers", "Full hand resting splint", "Dynamic finger extension splint"], correctIndex: 1, rationale: "Ulnar claw hand involves MCP hyperextension and IP flexion of the ring and little fingers. An MCP blocking splint prevents hyperextension, allowing the intact extrinsic extensors to extend the IP joints.", difficulty: 3, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-273", stem: "An OTA is helping an elderly client set up a medication management system. Which is the MOST effective approach for a client with mild memory impairment?", options: ["Verbal instructions only", "Weekly pill organizer with labeled compartments combined with an alarm-based reminder system", "Writing medication names on a napkin", "Trusting the client to remember without any aids"], correctIndex: 1, rationale: "A weekly pill organizer provides visual structure, and alarm reminders compensate for memory impairment, creating a dual-system approach that maximizes medication adherence.", difficulty: 1, category: "Patient Care Planning", topic: "Geriatric Rehabilitation" },
  { id: "ota-274", stem: "A client with an incomplete SCI at C8-T1 has intrinsic minus (claw) hand posture. What functional limitation does this cause?", options: ["Inability to flex the wrist", "Difficulty with fine motor precision and inability to flatten the hand for grasping flat objects", "Loss of shoulder flexion", "Inability to extend the elbow"], correctIndex: 1, rationale: "Intrinsic minus hand (loss of lumbricals and interossei) causes MCP hyperextension and IP flexion, limiting fine motor precision, flat hand activities, and effective grasp of large or flat objects.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "ota-275", stem: "An OTA is using the Model of Human Occupation (MOHO) to guide intervention for a retired client struggling with role loss. Which component should be primarily addressed?", options: ["Performance capacity — improving physical strength", "Habituation — restructuring daily routines and developing new meaningful roles", "Volition — assessing motor skills", "Environment — changing the client's housing"], correctIndex: 1, rationale: "Habituation in MOHO addresses roles and habits. A retired client with role loss needs help restructuring routines, identifying new meaningful roles, and establishing productive habits.", difficulty: 2, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "ota-276", stem: "During a functional capacity evaluation, a client can lift 20 lbs from floor to waist. According to the DOT physical demand levels, this falls into which category?", options: ["Sedentary (up to 10 lbs)", "Light (up to 20 lbs)", "Medium (up to 50 lbs)", "Heavy (up to 100 lbs)"], correctIndex: 1, rationale: "The DOT classifies physical demand levels: Sedentary (up to 10 lbs), Light (up to 20 lbs), Medium (20-50 lbs), Heavy (50-100 lbs), Very Heavy (over 100 lbs). Lifting 20 lbs falls in the Light category.", difficulty: 2, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-277", stem: "An OTA is treating a client who had a tendon transfer for radial nerve palsy. What is the MOST important post-operative intervention principle?", options: ["Immediately resume full activities", "Protect the transfer, re-educate the transferred muscle through motor learning, and progress gradually", "Apply maximum resistance to the transferred tendon", "Avoid all movement for 3 months"], correctIndex: 1, rationale: "Post-tendon transfer requires protecting the healing transfer, re-educating the transferred muscle in its new function through motor learning principles, and gradual progressive strengthening.", difficulty: 3, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-278", stem: "A client with hemiplegia is learning to open a jar one-handed. Which adapted method should the OTA teach?", options: ["Use a standard method with both hands", "Place the jar in a Dycem-lined drawer, close the drawer to stabilize, and twist the lid with the functioning hand", "Have the caregiver open all jars", "Use teeth to open jars"], correctIndex: 1, rationale: "The drawer method stabilizes the jar between the drawer walls (with Dycem for grip) while the functioning hand twists the lid, enabling one-handed jar opening for clients with hemiplegia.", difficulty: 2, category: "Therapeutic Intervention", topic: "Assistive Devices" },
  { id: "ota-279", stem: "An OTA is assessing a client's visual field. The client can only see objects in the right visual field of both eyes. What type of visual field deficit is this?", options: ["Right homonymous hemianopia", "Left homonymous hemianopia", "Bilateral blindness", "Tunnel vision"], correctIndex: 1, rationale: "Left homonymous hemianopia means loss of the left visual field in both eyes. The client can only see the right visual field, indicating damage to the right optic tract or visual cortex.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "ota-280", stem: "An OTA is working with a client who has a fear of falling after a hip fracture. Which intervention strategy addresses this specific issue?", options: ["Avoid all mobility training", "Graded exposure to mobility activities with progressively challenging balance tasks and fall prevention education", "Tell the client that falling is unlikely and resume full activity", "Only train transfers with maximum assist indefinitely"], correctIndex: 1, rationale: "Fear of falling (post-fall anxiety) is addressed through graded exposure to mobility activities, progressive balance training, fall prevention education, and building confidence through successful experiences.", difficulty: 2, category: "Therapeutic Intervention", topic: "Geriatric Rehabilitation" },
  { id: "ota-281", stem: "A client undergoing chemotherapy reports peripheral neuropathy in the hands. Which safety precaution should the OTA emphasize?", options: ["Use the affected hands for all hot item handling", "Test water temperature with unaffected body parts and use oven mitts, as impaired sensation increases burn risk", "Ignore the neuropathy as it will resolve", "Apply ice packs to improve sensation"], correctIndex: 1, rationale: "Chemotherapy-induced peripheral neuropathy impairs protective sensation. The OTA must teach compensatory safety strategies: testing water temperature, using protective equipment, and visually monitoring hand position.", difficulty: 2, category: "Safety", topic: "Rehabilitation Principles" },
  { id: "ota-282", stem: "An OTA is providing intervention for a client with ideomotor apraxia. What characterizes this condition?", options: ["The client cannot understand verbal commands", "The client knows what to do but cannot execute the correct motor plan on command despite intact motor function", "The client has complete paralysis", "The client has receptive aphasia"], correctIndex: 1, rationale: "Ideomotor apraxia is the inability to perform a motor act on command despite intact comprehension and motor ability. The client may perform the action automatically but fails when asked to demonstrate it.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "ota-283", stem: "A client with a brachial plexus injury (Erb-Duchenne palsy) cannot raise the arm. Which nerve roots are affected?", options: ["C8-T1", "C5-C6", "T2-T4", "L1-L3"], correctIndex: 1, rationale: "Erb-Duchenne palsy affects the upper trunk (C5-C6) of the brachial plexus, causing loss of shoulder abduction, external rotation, elbow flexion, and forearm supination ('waiter's tip' position).", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "ota-284", stem: "An OTA is adapting a computer workstation for ergonomic use. What is the recommended monitor height?", options: ["Below desk level", "Top of the screen at or slightly below eye level, approximately arm's length away", "Above head height to promote neck extension", "At waist level"], correctIndex: 1, rationale: "Ergonomic monitor placement: top of screen at or slightly below eye level to maintain neutral cervical spine position, approximately arm's length (20-26 inches) away to reduce eye strain.", difficulty: 1, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "ota-285", stem: "A client with an incomplete SCI demonstrates Brown-Séquard syndrome. What does this presentation include?", options: ["Complete loss of all motor and sensory function below the injury", "Ipsilateral motor loss and proprioception loss with contralateral pain and temperature loss", "Bilateral upper extremity weakness only", "Loss of only autonomic function below the injury"], correctIndex: 1, rationale: "Brown-Séquard syndrome (hemisection of the cord) causes ipsilateral motor paralysis and proprioception loss (dorsal column damage) with contralateral pain and temperature loss (spinothalamic tract damage).", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "ota-286", stem: "An OTA is teaching a client with low back pain proper body mechanics for lifting objects from the floor. What is the correct technique?", options: ["Bend at the waist with straight legs", "Bend at the knees and hips, keep the back straight, and hold the object close to the body", "Twist while lifting to reach the object", "Reach far away from the body with arms extended"], correctIndex: 1, rationale: "Proper body mechanics: bend at knees and hips (not waist), maintain natural spinal curves, hold the object close to the body to reduce lever arm, and avoid twisting during the lift.", difficulty: 1, category: "Safety", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-287", stem: "A client who had a CVA 6 months ago is at Brunnstrom Stage 5. What does this mean for upper extremity function?", options: ["No voluntary movement", "Only synergy-dependent movement", "Isolated, voluntary movements are possible with decreasing synergy influence", "Completely normal movement"], correctIndex: 2, rationale: "Brunnstrom Stage 5 features increasingly isolated voluntary movements outside synergy patterns. The client can perform more complex and varied movements with diminishing obligatory synergy influence.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "ota-288", stem: "An OTA is treating a client with bilateral hand contractures from scleroderma. Which intervention is MOST critical?", options: ["Only heat application without movement", "Sustained static progressive stretching combined with paraffin heat and active ROM to maintain tissue extensibility", "Waiting for the contractures to resolve spontaneously", "Surgical correction as first-line treatment"], correctIndex: 1, rationale: "Scleroderma causes progressive skin and tissue tightening. Paraffin heat increases tissue extensibility, followed by sustained stretching and active ROM to maintain hand function and prevent further contracture.", difficulty: 3, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-289", stem: "A client with traumatic brain injury is in Rancho Level IV. What behavior characterizes this level?", options: ["Purposeful and appropriate behavior", "Confused and agitated", "Generalized response to stimulation", "Localized response only"], correctIndex: 1, rationale: "Rancho Level IV (Confused-Agitated) is characterized by heightened state of activity, confusion, bizarre and non-purposeful behavior, incoherent verbalization, and inability to cooperate with treatment.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "ota-290", stem: "An OTA is teaching a client with hemiplegia to put on a button-front shirt. What is the correct sequence?", options: ["Affected arm first for donning, unaffected arm first for doffing", "Unaffected arm first for both donning and doffing", "Affected arm first for both donning and doffing", "Either arm can go first"], correctIndex: 0, rationale: "The rule for hemiplegic dressing: affected arm enters the sleeve first when donning, and the unaffected arm comes out first when doffing. This minimizes required ROM in the affected limb.", difficulty: 1, category: "Patient Care Planning", topic: "Neurological Rehabilitation" },
  { id: "ota-291", stem: "A client with upper extremity lymphedema following mastectomy asks about activity precautions. What should the OTA advise?", options: ["Avoid all upper extremity activity permanently", "Avoid blood pressure measurements, venipuncture, and constrictive clothing on the affected arm; progress exercise gradually", "Exercise aggressively to pump out the lymphatic fluid", "Apply tight compression continuously without monitoring"], correctIndex: 1, rationale: "Lymphedema precautions include avoiding blood pressure cuffs, needle sticks, and constrictive clothing on the affected arm. Exercise should be gradually progressed with compression garments as tolerated.", difficulty: 2, category: "Safety", topic: "Rehabilitation Principles" },
  { id: "ota-292", stem: "An OTA is treating a child with spastic hemiplegia who has difficulty with bimanual activities. Which therapeutic approach is appropriate?", options: ["Only working on the unaffected hand to maximize independence", "Hand-Arm Bimanual Intensive Therapy (HABIT) to train both hands working together during functional tasks", "Restraining both arms", "Focusing only on cognition without motor practice"], correctIndex: 1, rationale: "HABIT provides intensive bimanual training with structured practice of both hands working together during functional tasks, improving coordination between the affected and unaffected upper extremities.", difficulty: 3, category: "Therapeutic Intervention", topic: "Pediatric Rehabilitation" },
  { id: "ota-293", stem: "A client with spinal cord injury reports a change in bowel and bladder function alongside new bilateral lower extremity weakness. What should the OTA do?", options: ["Continue treatment as planned", "Stop treatment immediately and report to the supervising OT and medical team — these symptoms suggest a medical emergency", "Document the findings and report at the next team meeting", "Recommend the client rest and try again tomorrow"], correctIndex: 1, rationale: "New onset bowel/bladder changes with bilateral LE weakness could indicate cauda equina syndrome or other medical emergency. The OTA must stop treatment and report immediately for urgent evaluation.", difficulty: 2, category: "Safety", topic: "Neurological Rehabilitation" },
  { id: "ota-294", stem: "An OTA is adapting a toothbrush for a client with limited grip. Which modification is MOST effective?", options: ["Use a standard thin-handled toothbrush", "Build up the handle with foam tubing or use a universal cuff to strap the brush to the hand", "Switch to a water-only oral rinse", "Use a brush with a shorter handle"], correctIndex: 1, rationale: "Foam tubing increases handle diameter for clients with limited grip strength, and a universal cuff straps the utensil to the hand for clients who cannot maintain a voluntary grasp.", difficulty: 1, category: "Therapeutic Intervention", topic: "Assistive Devices" },
  { id: "ota-295", stem: "A client with Parkinson's disease has difficulty initiating movement to stand up from a chair. Which cueing strategy can help?", options: ["Wait silently until the client initiates movement", "Provide rhythmic auditory cues (counting '1-2-3 stand') or visual targets to facilitate movement initiation", "Pull the client to standing without warning", "Tell the client to try harder"], correctIndex: 1, rationale: "Parkinson's disease causes difficulty with motor initiation (akinesia). External cues — rhythmic auditory counting, visual targets, or verbal commands — help bypass basal ganglia dysfunction and facilitate movement.", difficulty: 2, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "ota-296", stem: "An OTA is setting up a child's classroom environment to support attention. Which modification is evidence-based?", options: ["Place the child's desk near the window for stimulation", "Position the desk away from high-traffic areas, use a visual schedule, and provide a seat cushion for sensory input", "Remove all visual supports from the classroom", "Have the child sit on the floor without a desk"], correctIndex: 1, rationale: "Environmental modifications for attention include reducing distractions (away from traffic/windows), visual schedules for predictability, and sensory supports (seat cushions) for alertness.", difficulty: 2, category: "Patient Care Planning", topic: "Pediatric Rehabilitation" },
  { id: "ota-297", stem: "A client is recovering from a Zone II flexor tendon injury (no man's land). Why is this zone particularly challenging for surgical repair?", options: ["The tendons are very thick in this area", "The FDS and FDP tendons run within a tight fibro-osseous sheath, increasing adhesion risk", "The tendons are not present in this zone", "This zone has excellent blood supply that causes excessive swelling"], correctIndex: 1, rationale: "Zone II ('no man's land') is challenging because both FDS and FDP tendons travel within a narrow fibro-osseous sheath, increasing the risk of adhesion formation between tendons and surrounding structures.", difficulty: 3, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-298", stem: "An OTA is treating an elderly client with a fear of falling who avoids leaving the house. Which frame of reference guides this intervention?", options: ["Biomechanical frame of reference", "Cognitive behavioral frame of reference — addressing maladaptive thoughts about falling and gradually increasing activity", "Neurodevelopmental treatment (NDT)", "Sensory integration framework"], correctIndex: 1, rationale: "Cognitive behavioral approaches address the maladaptive thought patterns (catastrophizing about falling) and avoidance behaviors through cognitive restructuring and graded behavioral activation.", difficulty: 2, category: "Patient Care Planning", topic: "Geriatric Rehabilitation" },
  { id: "ota-299", stem: "A client has a mallet finger injury. What is the characteristic deformity and splint position?", options: ["PIP flexion deformity; splint PIP in extension", "DIP flexion deformity (drooping fingertip); splint DIP in full extension or slight hyperextension", "MCP hyperextension; splint MCP in flexion", "Wrist drop; splint wrist in extension"], correctIndex: 1, rationale: "Mallet finger is caused by disruption of the terminal extensor tendon, resulting in DIP flexion (drooping fingertip). The DIP is splinted in full extension or slight hyperextension for 6-8 weeks.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-300", stem: "An OTA is evaluating a client's occupational performance using the Assessment of Motor and Process Skills (AMPS). What does this tool measure?", options: ["Isolated joint ROM and muscle strength", "Quality of motor and process skills during observed performance of familiar daily tasks", "Cognitive screening for dementia", "Sensory processing patterns"], correctIndex: 1, rationale: "The AMPS is a standardized observational assessment that evaluates the quality of motor and process (organizational/adaptive) skills during performance of chosen familiar daily living tasks in a natural context.", difficulty: 2, category: "Clinical Scenarios", topic: "Rehabilitation Principles" }
];
